(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,45466,e=>{"use strict";let a=[{slug:"alcides-ghiggia-1950",index:0,nom:"Alcides Ghiggia",surnom:null,pays:"Uruguay",mondial:"1950",poste:"Attaquant",image:"/cartes_itw/Ghiggia.png",titre_interview:"« Le pape, Frank Sinatra et moi »",lu:!1,archetype:"L'historien",archetype_justification:"Son récit est indissociable de la mémoire collective du « Maracanazo », un exploit qu'il a gravé à jamais dans l'histoire.",citations:{parcours_professionnel:["J’étais déjà fou de Penarol et j’ai débuté comme professionnel à Sud America.","J’ai eu l’honneur de porter le maillot de la Céleste, j’ai joué à l’AS Rome, à l’AC Milan et avec la Nazionale."],contexte_historique:["À cette époque-là, il n’y avait pas assez d’argent dans le monde pour jouer que les expatriés étaient mis à l’écart."],vie_equipe:["Penarol, c’est le club d’une vie, c’est mon sang. Comme parfois entre deux amants, il y a eu des orages."],ressentis_emotions:["Quand il y a des crises cardiaques, des morts, des suicides... Je me souviens de la fin et des gens qui pleuraient.","Il repasse presque tous les jours dans ma tête."],grands_moments_sportifs:["Je pars de loin sur un ballon en profondeur de Julio Pérez. Je dribble Bigode, je centre et là, je vois Barbosa, leur gardien, un peu avancé.","Je le répète, il n’y a que trois personnes au monde qui ont fait taire le Maracana : le pape, Frank Sinatra et moi."],technique_jeu:["Je ne suis pas grand mais j’ai de longues enjambées. Ma vitesse me permettait de déborder tout le monde."],ethique_justice:["Ils ont refusé. Les gouvernants de l’époque, déjà, avaient dit qu’avec le titre, les dirigeants de la Fédération recevraient une médaille d’or et nous, les joueurs, une médaille d’argent.","J’affirme qu’il a une dette envers nous tous, les champions. Je suis le dernier encore en vie."],anecdotes_vie_privee:["J’ai vendu mes voitures, mes maisons en Italie et finalement je suis rentré en Uruguay.","Les sorties la nuit, je laissais ça de côté. Et je n’ai jamais bu une goutte d’alcool."],preparation_condition_physique:["Une alimentation très saine et jamais d’alcool. Ah, si, juste une bière de temps en temps…","Enfant, j’habitais une rue en pente et je m’entraînais avec mon chien."],heritage_posterite:["Je signe des autographes tous les jours. Les anciens expliquent aux enfants que je suis celui qui, un jour, a fait pleurer le Brésil.","En 2009, j’ai été invité par la Fédération brésilienne... Ils ont fait un moulage de mes pieds"],psychologie_emotion:["Je suis un double survivant. Du Mondial de 1950 et d’un très grave accident de la circulation, fin décembre 2012."]},date_publication:"11/06/2014",resume:"« Le pape, Frank Sinatra et moi » ALCIDES GHIGGIA a marqué le but de la victoire de l'Uruguay contre le Brésil. Et pour lui, c’est simple : il est un des trois hommes à avoir fait taire le Maracana.",citation_forte:"J’étais déjà fou de Penarol et j’ai débuté comme professionnel à Sud America.",archetypes_ids:["l_historien","le_patriote","le_supporter"],theme_citations:{parcours_professionnel:"J’étais déjà fou de Penarol et j’ai débuté comme professionnel à Sud America.",contexte_historique:"À cette époque-là, il n’y avait pas assez d’argent dans le monde pour jouer que les expatriés étaient mis à l’écart.",vie_equipe:"Penarol, c’est le club d’une vie, c’est mon sang. Comme parfois entre deux amants, il y a eu des orages.",ressentis_emotions:"Quand il y a des crises cardiaques, des morts, des suicides... Je me souviens de la fin et des gens qui pleuraient.",grands_moments_sportifs:"Je pars de loin sur un ballon en profondeur de Julio Pérez. Je dribble Bigode, je centre et là, je vois Barbosa, leur gardien, un peu avancé.",technique_jeu:"Je ne suis pas grand mais j’ai de longues enjambées. Ma vitesse me permettait de déborder tout le monde.",ethique_justice:"Ils ont refusé. Les gouvernants de l’époque, déjà, avaient dit qu’avec le titre, les dirigeants de la Fédération recevraient une médaille d’or et nous, les joueurs, une médaille d’argent.",anecdotes_vie_privee:"J’ai vendu mes voitures, mes maisons en Italie et finalement je suis rentré en Uruguay.",preparation_condition_physique:"Une alimentation très saine et jamais d’alcool. Ah, si, juste une bière de temps en temps…",heritage_posterite:"Je signe des autographes tous les jours. Les anciens expliquent aux enfants que je suis celui qui, un jour, a fait pleurer le Brésil.",psychologie_emotion:"Je suis un double survivant. Du Mondial de 1950 et d’un très grave accident de la circulation, fin décembre 2012."},joueur:"Alcides Ghiggia",temps_lecture:"9 min"},{slug:"pele-1958",index:1,nom:"Edson Arantes do Nascimento",surnom:"Pelé",pays:"Brésil",mondial:"1958, 1962, 1970",poste:"Attaquant",image:"/cartes_itw/Pelé.png",titre_interview:"« Mon père me disait souvent que mon football inspirerait les gens »",lu:!1,archetype:"L'artiste",archetype_justification:"Il considérait son football comme une source d'inspiration et de magie, cherchant toujours à inventer des gestes inoubliables.",citations:{parcours_professionnel:["Je jouais à Santos, qui était le meilleur club brésilien. Avant le Mondial 1962, nous avions disputé beaucoup de matches d’exhibition à l’étranger, en France, au Mexique..."],contexte_historique:["Ce Mondial est d’ailleurs encore considéré comme un des plus violents de l’histoire. Beaucoup d’autres joueurs ont été blessés."],vie_equipe:["Nous avions quatre joueurs remarquables évoluant au même poste, celui de numéro 10. Il y avait donc Pelé, n° 10 de Santos, mais aussi Rivelino, n° 10 des Corinthians ; Tostao, n°10 à Cruzeiro ; et Gerson, n° 10 à Botafogo."],ressentis_emotions:["Je pleurais parce que j’étais très ému : jouer et gagner une Coupe du monde à mon âge...","Encore aujourd’hui, l’image de mon père en train de pleurer me hante."],grands_moments_sportifs:["C’est un but assez avant-gardiste. Sur un centre dans la surface, je contrôle le ballon de la poitrine, j’enchaîne par un lob sur le défenseur. Je me retrouve seul face au gardien..."],technique_jeu:["Beaucoup me demandent comment j’ai fait pour marquer de la tête du haut de mon 1,70 m. Ma réponse est toujours la même. Tout simplement parce que le gardien ne s’appelait pas Banks."],ethique_justice:["Certains ont dit que les défenseurs agissaient ainsi contre moi par jalousie mais je ne le crois pas. Ce genre de gestes était courant lors d’un match important."],anecdotes_vie_privee:["J’étais en Suède, c’était mon premier déplacement hors du Brésil, et en plus sans ma famille.","Je me souviens avoir passé un coup de fil à mon père depuis le stade."],preparation_condition_physique:["J’avais été blessé au pied quelques semaines avant le tournoi, lors d’un match de Championnat (de Santos) contre les Corinthians."],heritage_posterite:["Mon père me disait souvent que mon football inspirerait les gens."],psychologie_emotion:["Si l’on pense qu’on est le meilleur, alors quelqu’un finit toujours par vous passer devant.","J’ai réussi tout ça sans jamais ressentir la moindre pression. Vraiment !"]},date_publication:"12/06/2014",resume:"vos quatre Coupes du monde, il y a bien sûr des archives vidéo célèbres de gestes et de buts légendaires.",citation_forte:"Je jouais à Santos, qui était le meilleur club brésilien. Avant le Mondial 1962, nous avions disputé beaucoup de matches d’exhibition à l’étranger, en France, au Mexique...",archetypes_ids:["le_curieux"],theme_citations:{parcours_professionnel:"Je jouais à Santos, qui était le meilleur club brésilien. Avant le Mondial 1962, nous avions disputé beaucoup de matches d’exhibition à l’étranger, en France, au Mexique...",contexte_historique:"Ce Mondial est d’ailleurs encore considéré comme un des plus violents de l’histoire. Beaucoup d’autres joueurs ont été blessés.",vie_equipe:"Nous avions quatre joueurs remarquables évoluant au même poste, celui de numéro 10. Il y avait donc Pelé, n° 10 de Santos, mais aussi Rivelino, n° 10 des Corinthians ; Tostao, n°10 à Cruzeiro ; et Gerson, n° 10 à Botafogo.",ressentis_emotions:"Je pleurais parce que j’étais très ému : jouer et gagner une Coupe du monde à mon âge...",grands_moments_sportifs:"C’est un but assez avant-gardiste. Sur un centre dans la surface, je contrôle le ballon de la poitrine, j’enchaîne par un lob sur le défenseur. Je me retrouve seul face au gardien...",technique_jeu:"Beaucoup me demandent comment j’ai fait pour marquer de la tête du haut de mon 1,70 m. Ma réponse est toujours la même. Tout simplement parce que le gardien ne s’appelait pas Banks.",ethique_justice:"Certains ont dit que les défenseurs agissaient ainsi contre moi par jalousie mais je ne le crois pas. Ce genre de gestes était courant lors d’un match important.",anecdotes_vie_privee:"J’étais en Suède, c’était mon premier déplacement hors du Brésil, et en plus sans ma famille.",preparation_condition_physique:"J’avais été blessé au pied quelques semaines avant le tournoi, lors d’un match de Championnat (de Santos) contre les Corinthians.",heritage_posterite:"Mon père me disait souvent que mon football inspirerait les gens.",psychologie_emotion:"Si l’on pense qu’on est le meilleur, alors quelqu’un finit toujours par vous passer devant."},joueur:"Edson Arantes do Nascimento",temps_lecture:"10 min"},{slug:"dobromir-jetchev-1966",index:2,nom:"Dobromir Jetchev",surnom:null,pays:"Bulgarie",mondial:"1966",poste:"Défenseur",image:"/cartes_itw/Dobromir.png",titre_interview:"« Disons que j’étais un peu sauvage... »",lu:!1,archetype:"Le curieux",archetype_justification:"Il apporte un éclairage insolite sur le football derrière le rideau de fer et ses duels « sauvages » contre les stars.",citations:{parcours_professionnel:["J’ai participé à quatre Coupes du monde (de 1960 à 1974), à une époque où les Bulgares ne pouvaient pas jouer à l’étranger."],contexte_historique:["Un jour, à l’occasion d’un match de qualifications à la Coupe du monde, aux Pays-Bas, l’entraîneur de l’Eintracht Francfort m’a proposé de passer à l’Ouest. Mais j’étais marié. On ne peut pas fuir et laisser sa famille, la mettre en danger."],vie_equipe:["Notre entraîneur était tchèque et, à vrai dire, je n’étais pas trop d’accord avec ses manières."],ressentis_emotions:["Une heure et demie avant le match, nous sommes sortis pour attendre le car. Tout le monde chantait : “Victoire, victoire, victoire”. On avait la chair de poule."],grands_moments_sportifs:["C’est simple : d’entrée, je le tacle, je prends le ballon. Et il comprend que ce sera difficile pour lui."],technique_jeu:["Je devais m’occuper du joueur adverse le plus dangereux : Eusebio (Portugal), Pelé (Brésil), Van Himst (Belgique), Riva (Italie), Albert (Hongrie), ils étaient tous pour moi.","Et la surprise, c’était le jeu de Pelé sans ballon. On n’était pas préparés à ça."],ethique_justice:["J’étais dur, particulièrement lors de mes premières interventions, mais j’essayais toujours de sortir du duel avec le ballon.","Si un joueur a peur, il va prendre des coups, s’il n’a pas peur, il va les éviter, c’est aussi simple que ça."],anecdotes_vie_privee:["Avec Asparoukhov, nous avons obtenu très vite un appartement dans le même immeuble, alors qu’il fallait normalement attendre des années."],preparation_condition_physique:["Je n’avais pas peur. Je ne me souviens pas avoir eu peur avant un match."],heritage_posterite:["Je suis célèbre, grâce à cette réputation. Vous seriez venu me voir, sinon ?"],psychologie_emotion:["Disons que j’étais un peu sauvage. Je ne voulais pas parler. Je le regardais comme ça. Il devait savoir, d’entrée, que je serais très dur."]},date_publication:"13/06/2014",resume:"un journaliste de L’Équipe est venu vous voir, ici,. – Oui, j’avais fait des photos avec le maillot de Pelé. Vous lui aviez surtout dit : “J’ai commencé le travail, Morais l’a fini.” – C’est la vérité.",citation_forte:"J’ai participé à quatre Coupes du monde (de 1960 à 1974), à une époque où les Bulgares ne pouvaient pas jouer à l’étranger.",archetypes_ids:["l_historien","le_curieux","le_stratege"],theme_citations:{parcours_professionnel:"J’ai participé à quatre Coupes du monde (de 1960 à 1974), à une époque où les Bulgares ne pouvaient pas jouer à l’étranger.",contexte_historique:"Un jour, à l’occasion d’un match de qualifications à la Coupe du monde, aux Pays-Bas, l’entraîneur de l’Eintracht Francfort m’a proposé de passer à l’Ouest. Mais j’étais marié. On ne peut pas fuir et laisser sa famille, la mettre en danger.",vie_equipe:"Notre entraîneur était tchèque et, à vrai dire, je n’étais pas trop d’accord avec ses manières.",ressentis_emotions:"Une heure et demie avant le match, nous sommes sortis pour attendre le car. Tout le monde chantait : “Victoire, victoire, victoire”. On avait la chair de poule.",grands_moments_sportifs:"C’est simple : d’entrée, je le tacle, je prends le ballon. Et il comprend que ce sera difficile pour lui.",technique_jeu:"Je devais m’occuper du joueur adverse le plus dangereux : Eusebio (Portugal), Pelé (Brésil), Van Himst (Belgique), Riva (Italie), Albert (Hongrie), ils étaient tous pour moi.",ethique_justice:"J’étais dur, particulièrement lors de mes premières interventions, mais j’essayais toujours de sortir du duel avec le ballon.",anecdotes_vie_privee:"Avec Asparoukhov, nous avons obtenu très vite un appartement dans le même immeuble, alors qu’il fallait normalement attendre des années.",preparation_condition_physique:"Je n’avais pas peur. Je ne me souviens pas avoir eu peur avant un match.",heritage_posterite:"Je suis célèbre, grâce à cette réputation. Vous seriez venu me voir, sinon ?",psychologie_emotion:"Disons que j’étais un peu sauvage. Je ne voulais pas parler. Je le regardais comme ça. Il devait savoir, d’entrée, que je serais très dur."},joueur:"Dobromir Jetchev",temps_lecture:"9 min"},{slug:"roger-milla-1990",index:3,nom:"Roger Milla",surnom:"Le Roi des Lions",pays:"Cameroun",mondial:"1990",poste:"Attaquant",image:"/cartes_itw/Milla.png",titre_interview:"« Les gens disaient en me voyant : c’est lui...? »",lu:!1,archetype:"Amoureux du maillot",archetype_justification:"Véritable symbole national, il a toujours clamé jouer avant tout pour son pays et pour le peuple qui le réclamait.",citations:{parcours_professionnel:["Le chef de l’État me nomme directeur administratif des équipes nationales. Je ne jouais plus depuis 1990, sauf des jubilés."],contexte_historique:["Si l’Africain avait été plus considéré à cette époque, j’aurais été vu comme un grand joueur.","À l’époque, avec le passeport camerounais, on pouvait aller dans tous les pays sauf en Afsud, c’était écrit noir sur blanc !"],vie_equipe:["Le ministre des Sports, lui-même, avait tenu une réunion, avec les autres joueurs, pour me fracasser !","On préparait tous nos matches dans des dortoirs. On mangeait comme les militaires, il n’y avait pas de clim, rien…"],ressentis_emotions:["Quand on m’a annoncé son décès (le 5 décembre dernier), je me suis mis dans un coin pour pleurer quinze ou vingt minutes."],grands_moments_sportifs:["Je marque d’une reprise de volée. Même les supporters du Canon ont fait arrêter le match pendant cinq minutes pour applaudir.","Et j’entre dans l’histoire de la Coupe du monde ! Même le roi Pelé ne l’a pas fait."],technique_jeu:["Quand vous êtes un génie, vous le restez. C’est le destin de chaque individu sur cette Terre."],ethique_justice:["Le même ministre, qui voulait me virer, est venu me voir pour dire qu’il me donnerait une prime de 200 000 francs CFA (environ 300 euros) à chacun de mes buts… Pas question ! Je jouais pour mon pays."],anecdotes_vie_privee:["Mon père était cheminot et ma mère ménagère. Nous avons grandi comme si on était les plus riches du monde. Je n’ai jamais manqué de rien."],preparation_condition_physique:["J’ai alors bossé comme un dingue, avec un préparateur physique, dans une petite forêt à côté de la présidence.","On se levait à 4 heures pour le footing et l’entraînement était à 9 heures."],heritage_posterite:["Il m’est arrivé de ne pas avoir eu besoin de montrer mon passeport pour passer des frontières...","Je suis devenu une légende pour la Coupe du monde."],psychologie_emotion:["Je n’ai jamais été un tricheur.","Si je n’avais pas été travailleur, j’aurais abandonné. Ma préoccupation, c’était le Cameroun."]},date_publication:"14/06/2014",resume:"avec la Coupe du monde est faite de moments très forts. Par exemple, sans l’intervention de Paul Biya (le président camerounais, toujours en poste), vous n’auriez jamais dû disputer celle de 1990, en Italie.",citation_forte:"Le chef de l’État me nomme directeur administratif des équipes nationales. Je ne jouais plus depuis 1990, sauf des jubilés.",archetypes_ids:["le_patriote","le_curieux","l_historien"],theme_citations:{parcours_professionnel:"Le chef de l’État me nomme directeur administratif des équipes nationales. Je ne jouais plus depuis 1990, sauf des jubilés.",contexte_historique:"Si l’Africain avait été plus considéré à cette époque, j’aurais été vu comme un grand joueur.",vie_equipe:"Le ministre des Sports, lui-même, avait tenu une réunion, avec les autres joueurs, pour me fracasser !",ressentis_emotions:"Quand on m’a annoncé son décès (le 5 décembre dernier), je me suis mis dans un coin pour pleurer quinze ou vingt minutes.",grands_moments_sportifs:"Je marque d’une reprise de volée. Même les supporters du Canon ont fait arrêter le match pendant cinq minutes pour applaudir.",technique_jeu:"Quand vous êtes un génie, vous le restez. C’est le destin de chaque individu sur cette Terre.",ethique_justice:"Le même ministre, qui voulait me virer, est venu me voir pour dire qu’il me donnerait une prime de 200 000 francs CFA (environ 300 euros) à chacun de mes buts… Pas question ! Je jouais pour mon pays.",anecdotes_vie_privee:"Mon père était cheminot et ma mère ménagère. Nous avons grandi comme si on était les plus riches du monde. Je n’ai jamais manqué de rien.",preparation_condition_physique:"J’ai alors bossé comme un dingue, avec un préparateur physique, dans une petite forêt à côté de la présidence.",heritage_posterite:"Il m’est arrivé de ne pas avoir eu besoin de montrer mon passeport pour passer des frontières...",psychologie_emotion:"Je n’ai jamais été un tricheur."},joueur:"Roger Milla",temps_lecture:"10 min"},{slug:"stephane-meunier-1998",index:4,nom:"Stéphane Meunier",surnom:null,pays:"France",mondial:"1998",poste:"Réalisateur",image:"/cartes_itw/Meunier.png",titre_interview:"« Ils voulaient un souvenir, un film de vacances »",lu:!1,archetype:"Le curieux",archetype_justification:"En tant que réalisateur, il a exploré l'intimité et les coulisses des Bleus de 1998, révélant la face cachée du groupe.",citations:{parcours_professionnel:["Avec Capa, j’ai tourné dans un monastère à Jérusalem avec l’armée sur le toit, en Afrique du Sud sous l’apartheid, à Sarajevo…"],contexte_historique:["À l’époque, il n’y avait pas cette culture, la téléréalité n’existait pas. Le sport, c’était l’événement en direct et basta  !","Tout à coup, la France s’est aperçue qu’elle pouvait aimer les vainqueurs. Avant, le foot, c’était un sport de blaireaux."],vie_equipe:["Ce n’est pas encore le Zidane d’après, ce n’est pas encore “Dieu”. Mais il inspire déjà quelque chose, il ne revendique rien, mais tout le monde le regarde.","Leur confiance s’est renforcée au fur et à mesure, mais je n’ai jamais senti de fébrilité."],ressentis_emotions:["Quand les gens s’adressent à moi, ce n’est pas pour découvrir des trucs, c’est pour revisiter un moment de ce bonheur-là."],grands_moments_sportifs:["Comme le quart de finale (France-Italie) où je suis tellement dans cette énergie-là que je capte le mec qui dit ce qui va se passer."],technique_jeu:["Je ne comprenais pas les entraînements. Si tu es trop attaché au sport, tu commences à décrypter."],ethique_justice:["J’ai fini le montage le 13 juillet et je l’ai seulement montré à Aimé, à Clairefontaine, comme on en était convenu. Il m’a demandé à faire sauter un plan. C’est tout."],anecdotes_vie_privee:["Une semaine après le Mondial, je suis parti en vacances : j’avais une angine blanche, un torticolis et une double entorse."],preparation_condition_physique:["Le premier qui se lève me voit, le dernier qui se couche à 2 heures du mat me voit. Je dors trois heures par nuit. Tout le temps aux aguets."],heritage_posterite:["Pour tout le monde, il y a la Coupe du monde et “les Yeux”. Même pour moi. Tu ne peux pas faire un truc comme ça et passer à autre chose."],psychologie_emotion:["Je ne suis pas dans l’empathie au départ. Je suis un guerrier.","Je suis un radar, mon cerveau tourne à 2 000 à l’heure."]},date_publication:"15/06/2014",resume:"Entre le montage de son premier long métrage (la Grande Séduction), dont la sortie est prévue cet hiver, ou le tournage d’une série pour France Ô, l’ancien journaliste passé à la réalisation est un homme pressé.",citation_forte:"Avec Capa, j’ai tourné dans un monastère à Jérusalem avec l’armée sur le toit, en Afrique du Sud sous l’apartheid, à Sarajevo…",archetypes_ids:["l_artiste","le_supporter"],theme_citations:{parcours_professionnel:"Avec Capa, j’ai tourné dans un monastère à Jérusalem avec l’armée sur le toit, en Afrique du Sud sous l’apartheid, à Sarajevo…",contexte_historique:"À l’époque, il n’y avait pas cette culture, la téléréalité n’existait pas. Le sport, c’était l’événement en direct et basta !",vie_equipe:"Ce n’est pas encore le Zidane d’après, ce n’est pas encore “Dieu”. Mais il inspire déjà quelque chose, il ne revendique rien, mais tout le monde le regarde.",ressentis_emotions:"Quand les gens s’adressent à moi, ce n’est pas pour découvrir des trucs, c’est pour revisiter un moment de ce bonheur-là.",grands_moments_sportifs:"Comme le quart de finale (France-Italie) où je suis tellement dans cette énergie-là que je capte le mec qui dit ce qui va se passer.",technique_jeu:"Je ne comprenais pas les entraînements. Si tu es trop attaché au sport, tu commences à décrypter.",ethique_justice:"J’ai fini le montage le 13 juillet et je l’ai seulement montré à Aimé, à Clairefontaine, comme on en était convenu. Il m’a demandé à faire sauter un plan. C’est tout.",anecdotes_vie_privee:"Une semaine après le Mondial, je suis parti en vacances : j’avais une angine blanche, un torticolis et une double entorse.",preparation_condition_physique:"Le premier qui se lève me voit, le dernier qui se couche à 2 heures du mat me voit. Je dors trois heures par nuit. Tout le temps aux aguets.",heritage_posterite:"Pour tout le monde, il y a la Coupe du monde et “les Yeux”. Même pour moi. Tu ne peux pas faire un truc comme ça et passer à autre chose.",psychologie_emotion:"Je ne suis pas dans l’empathie au départ. Je suis un guerrier."},joueur:"Stéphane Meunier",temps_lecture:"10 min"},{slug:"bernard-lacombe-1978",index:5,nom:"Bernard Lacombe",surnom:null,pays:"France",mondial:"1978",poste:"Attaquant",image:"/cartes_itw/Lacombe.png",titre_interview:"« Didier Six centre, j’arrive pour couper la trajectoire. Voilà »",lu:!1,archetype:"L'historien",archetype_justification:"Il garde une mémoire précise de son record et de l'atmosphère mythique des stades argentins de 1978.",citations:{parcours_professionnel:[],contexte_historique:["En 1978, personne n’avait fait mieux. Une fois rentré en France, je regardais la première minute des matches, mais après ce n’était plus la peine."],vie_equipe:["L’autre avant-centre, c’était Marc Berdoll. Il fumait comme un pompier et, pour se motiver, il avait dans sa valise la gnôle de son grand-père.","On partageait le même hôtel, à l’Hindu Club, à Buenos Aires. On était au huitième étage et eux au niveau en dessous. Sur le terrain d’entraînement on se succédait..."],ressentis_emotions:["J’ai vécu les tirs au but depuis la tribune et je suis descendu dans le vestiaire après. Tout le monde pleurait.","Il a fallu repartir de Séville dans la nuit, retrouver les Allemands dans l’aéroport à deux heures du matin, et quand on est arrivés, ils étaient en train de discuter avec l’arbitre."],grands_moments_sportifs:["Sur la prise de balle, son contrôle orienté, Didier prend deux mètres d’avance, qu’il va garder jusqu’au bout. Il centre, et j’arrive pour couper la trajectoire de la tête. Voilà.","On avait fait match nul à Naples (2-2), en février, le jour où Michel (Platini) a inscrit deux coups francs à Zoff."],technique_jeu:[],ethique_justice:["En décembre, pendant notre stage à Font-Romeu, on avait demandé que la prime habituelle soit revalorisée pour la Coupe du monde. Avec le recul, c’était “fifrelot”...","J’ai pensé aux arbitres, quand même… C’était M. Corver, le Hollandais. Rien ne le gênait pour voir exactement ce qui s’était passé entre Schumacher et Battiston, et il n’avait rien dit."],anecdotes_vie_privee:["Quand je suis arrivé à l’OL, la première année où j’ai joué en pros (1969), à dix-huit ans, je gagnais 1 500 francs par mois.","La veille, après la conférence de presse, un monsieur s’était approché de moi pour me glisser : “Tu sais que tu as le même numéro que moi en 1958 ?” C’était “Justo” Fontaine."],preparation_condition_physique:[],heritage_posterite:["Aujourd’hui encore, dans le TGV, on me reparle de ce but. Les gens, souvent, me décrivent où ils étaient ce jour-là.","C’est un chrono en or de très grande valeur. En 1997, pendant le Tournoi de France, la mairie de Lyon m’a demandé de l’exposer en vitrine et l’avait assuré pour très cher. On l’a remis au coffre, depuis…"],psychologie_emotion:["À ce moment-là, plein de choses te passent par la tête. Tu penses à tes proches restés en France."]},date_publication:"16/06/2014",resume:"« Didier Six centre, j’arrive pour couper la trajectoire. Voilà » BERNARD LACOMBE a inscrit, au bout de 38 secondes face à l’Italie, en 1978, un but qui fut, à l’époque, le plus rapide de l’histoire de la Coupe du monde.",citation_forte:"En 1978, personne n’avait fait mieux. Une fois rentré en France, je regardais la première minute des matches, mais après ce n’était plus la peine.",archetypes_ids:["l_historien","le_supporter","le_stratege"],theme_citations:{contexte_historique:"En 1978, personne n’avait fait mieux. Une fois rentré en France, je regardais la première minute des matches, mais après ce n’était plus la peine.",vie_equipe:"L’autre avant-centre, c’était Marc Berdoll. Il fumait comme un pompier et, pour se motiver, il avait dans sa valise la gnôle de son grand-père.",ressentis_emotions:"J’ai vécu les tirs au but depuis la tribune et je suis descendu dans le vestiaire après. Tout le monde pleurait.",grands_moments_sportifs:"Sur la prise de balle, son contrôle orienté, Didier prend deux mètres d’avance, qu’il va garder jusqu’au bout. Il centre, et j’arrive pour couper la trajectoire de la tête. Voilà.",ethique_justice:"En décembre, pendant notre stage à Font-Romeu, on avait demandé que la prime habituelle soit revalorisée pour la Coupe du monde. Avec le recul, c’était “fifrelot”...",anecdotes_vie_privee:"Quand je suis arrivé à l’OL, la première année où j’ai joué en pros (1969), à dix-huit ans, je gagnais 1 500 francs par mois.",heritage_posterite:"Aujourd’hui encore, dans le TGV, on me reparle de ce but. Les gens, souvent, me décrivent où ils étaient ce jour-là.",psychologie_emotion:"À ce moment-là, plein de choses te passent par la tête. Tu penses à tes proches restés en France."},joueur:"Bernard Lacombe",temps_lecture:"9 min"},{slug:"rabah-madjer-1982",index:6,nom:"Rabah Madjer",surnom:null,pays:"Algérie",mondial:"1982",poste:"Attaquant",image:"/cartes_itw/Madjer.png",titre_interview:"« C’est comme si on nous avait coupé les pieds »",lu:!1,archetype:"L'historien",archetype_justification:"Son témoignage se concentre sur le récit d'une injustice historique (le match de la honte) qui a marqué le football algérien.",citations:{parcours_professionnel:["Après notre victoire en Coupe d’Europe des clubs champions avec Porto en 1987 (2-1, face au Bayern Munich), je devais m’engager avec le Bayern."],contexte_historique:["On pouvait aller très loin dans cette compétition, malgré notre inexpérience, et cette injustice a brisé nombre de destins."],vie_equipe:["Pour nous décontracter, on avait mis à fond une cassette du groupe El Bahara, qui avait composé une chanson pour l’équipe nationale."],ressentis_emotions:["Nous nous sommes tous levés comme un seul homme pour exprimer notre dégoût, notre rage. En fait, c’est bien simple, on voulait tout casser à l’hôtel.","Je me souviens de la détresse de tous. Je n’avais jamais ressenti une telle tristesse."],grands_moments_sportifs:["C’était la première fois qu’une petite nation battait la grande Allemagne de Hrubesch, Rummenigge, Breitner, Schumacher, Dremmler lors d’un Mondial."],technique_jeu:[],ethique_justice:["Quand on a vu ça, on a immédiatement compris que le match avait été arrangé, que les joueurs des deux équipes s’étaient mis d’accord entre eux.","Toutes ces magouilles, cela existe toujours. La corruption est partout et pas seulement en Afrique, comme on a un peu trop tendance à le croire."],anecdotes_vie_privee:[],preparation_condition_physique:[],heritage_posterite:["Finalement, à bien y réfléchir, nous, les petits Algériens, malgré nous, avons fait évoluer les règlements de la FIFA. Nous sommes entrés dans l’histoire...","Beaucoup, par la suite, se sont excusés. C’est bien de reconnaître le mal que l’on a fait, mais qu’est-ce que cela change pour nous ?"],psychologie_emotion:["Je suis un professionnel avant tout et je vais même vous dire une chose : je ne suis pas rancunier.","Au début, face aux Allemands, on était tétanisés, puis on a compris. On a commencé à jouer et on les a battus."]},date_publication:"17/06/2014",resume:"« C’est comme si on nous avait coupé les pieds » RABAH MADJER raconte la douleur ressentie par l’équipe d’Algérie après le « match de la honte » entre Allemagne et Autriche (1-0), qui l’éliminait de la compétition.",citation_forte:"Après notre victoire en Coupe d’Europe des clubs champions avec Porto en 1987 (2-1, face au Bayern Munich), je devais m’engager avec le Bayern.",archetypes_ids:["le_patriote","le_curieux","le_supporter"],theme_citations:{parcours_professionnel:"Après notre victoire en Coupe d’Europe des clubs champions avec Porto en 1987 (2-1, face au Bayern Munich), je devais m’engager avec le Bayern.",contexte_historique:"On pouvait aller très loin dans cette compétition, malgré notre inexpérience, et cette injustice a brisé nombre de destins.",vie_equipe:"Pour nous décontracter, on avait mis à fond une cassette du groupe El Bahara, qui avait composé une chanson pour l’équipe nationale.",ressentis_emotions:"Nous nous sommes tous levés comme un seul homme pour exprimer notre dégoût, notre rage. En fait, c’est bien simple, on voulait tout casser à l’hôtel.",grands_moments_sportifs:"C’était la première fois qu’une petite nation battait la grande Allemagne de Hrubesch, Rummenigge, Breitner, Schumacher, Dremmler lors d’un Mondial.",ethique_justice:"Quand on a vu ça, on a immédiatement compris que le match avait été arrangé, que les joueurs des deux équipes s’étaient mis d’accord entre eux.",heritage_posterite:"Finalement, à bien y réfléchir, nous, les petits Algériens, malgré nous, avons fait évoluer les règlements de la FIFA. Nous sommes entrés dans l’histoire...",psychologie_emotion:"Je suis un professionnel avant tout et je vais même vous dire une chose : je ne suis pas rancunier."},joueur:"Rabah Madjer",temps_lecture:"9 min"},{slug:"asamoah-gyan-2010",index:7,nom:"Asamoah Gyan",surnom:"Baby Jet",pays:"Ghana",mondial:"2010",poste:"Attaquant",image:"/cartes_itw/Gyan.png",titre_interview:"« J’ai raté le penalty le plus important de toute notre histoire »",lu:!1,archetype:"Amoureux du maillot",archetype_justification:"Il porte en lui la fierté du Ghana et de l'Afrique, vivant ses succès et ses échecs comme un destin national.",citations:{parcours_professionnel:["J'ai fait mes débuts en 2003, à dix-sept ans, et le Ghana s’est qualifié pour sa première Coupe du monde (en 2006) !"],contexte_historique:["Pour la première fois, une équipe du continent pouvait arriver en demi-finales de la Coupe du monde. Il suffisait que je marque."],vie_equipe:["Les joueurs m’ont réconforté car ils savent tous ce que je vaux. Tout le monde s’est senti mal pour moi."],ressentis_emotions:["J’étais détruit, brisé… À terre. J’ai eu l’impression d’avoir laissé tomber tout le monde, non seulement le Ghana, mais aussi l’Afrique.","Non, je n’ai pas fermé l’œil. Pendant un mois, je n’ai d’ailleurs pas pu dormir ou presque..."],grands_moments_sportifs:["J’étais confiant, j’ai pris la balle, je l’ai placée à terre et voilà… Je dois vous l’avouer, quand je suis seul, parfois cette image me hante.","Depuis 2010, je l’ai vu au moins vingt fois en DVD. Je le regarde encore et encore pour voir ce qui n’est pas allé."],technique_jeu:[],ethique_justice:["C’était une tricherie, mais Suarez a sauvé sa patrie. On doit l’accepter.","Si j’avais été à sa place, j’aurais fait pareil. Il pouvait bien ensuite faire un tour d’honneur et moi pleurer. C’était à moi d’écrire l’histoire et je ne l’ai pas fait..."],anecdotes_vie_privee:["La seule chose qu’elle m’a demandée, c’est de ne plus tirer pour l’équipe nationale après mon raté en demi-finales de la CAN 2012, contre la Zambie. Celui-là avait été de trop."],preparation_condition_physique:["Pendant mon break, j’ai beaucoup pensé à ces deux penalties ratés, je devais sortir ça de mon esprit. J’ai passé du temps avec ma famille, je me suis remis."],heritage_posterite:["Même si c’est l’un des moments les plus tristes que j’aie vécus, j’ai grandi, j’ai mûri. Je ne suis plus le même depuis."],psychologie_emotion:["J’ai eu des hauts et des bas dans ma carrière. J’ai été critiqué, mais tu dois survivre en étant fort mentalement.","La douleur était telle que je devais passer au-dessus, me relever, ne pas rester la tête baissée. Ce tir au but réussi a eu un impact immense dans ma carrière."]},date_publication:"18/06/2014",resume:"« J’ai raté le penalty le plus important de toute notre histoire » ASAMOAH GYAN a beaucoup souffert de son penalty raté face à l’Uruguay, en 2010, qui aurait permis au Ghana d’être le premier pays africain à disputer une demi-finale de la...",citation_forte:"J'ai fait mes débuts en 2003, à dix-sept ans, et le Ghana s’est qualifié pour sa première Coupe du monde (en 2006) !",archetypes_ids:["le_patriote","le_stratege","le_curieux"],theme_citations:{parcours_professionnel:"J'ai fait mes débuts en 2003, à dix-sept ans, et le Ghana s’est qualifié pour sa première Coupe du monde (en 2006) !",contexte_historique:"Pour la première fois, une équipe du continent pouvait arriver en demi-finales de la Coupe du monde. Il suffisait que je marque.",vie_equipe:"Les joueurs m’ont réconforté car ils savent tous ce que je vaux. Tout le monde s’est senti mal pour moi.",ressentis_emotions:"J’étais détruit, brisé… À terre. J’ai eu l’impression d’avoir laissé tomber tout le monde, non seulement le Ghana, mais aussi l’Afrique.",grands_moments_sportifs:"J’étais confiant, j’ai pris la balle, je l’ai placée à terre et voilà… Je dois vous l’avouer, quand je suis seul, parfois cette image me hante.",ethique_justice:"C’était une tricherie, mais Suarez a sauvé sa patrie. On doit l’accepter.",anecdotes_vie_privee:"La seule chose qu’elle m’a demandée, c’est de ne plus tirer pour l’équipe nationale après mon raté en demi-finales de la CAN 2012, contre la Zambie. Celui-là avait été de trop.",preparation_condition_physique:"Pendant mon break, j’ai beaucoup pensé à ces deux penalties ratés, je devais sortir ça de mon esprit. J’ai passé du temps avec ma famille, je me suis remis.",heritage_posterite:"Même si c’est l’un des moments les plus tristes que j’aie vécus, j’ai grandi, j’ai mûri. Je ne suis plus le même depuis.",psychologie_emotion:"J’ai eu des hauts et des bas dans ma carrière. J’ai été critiqué, mais tu dois survivre en étant fort mentalement."},joueur:"Asamoah Gyan",temps_lecture:"7 min"},{slug:"joel-quiniou-1986",index:8,nom:"Joël Quiniou",surnom:null,pays:"France",mondial:"1986, 1990, 1994",poste:"Arbitre",image:"/cartes_itw/Quiniou.png",titre_interview:"« Je ne l’ai pas sorti pour entrer dans le Livre des records ! »",lu:!1,archetype:"Le stratège",archetype_justification:"Son approche est celle d'un garant des lois du jeu, focalisé sur la rigueur et l'analyse réglementaire des actions.",citations:{parcours_professionnel:["La Coupe du monde aux États-Unis représente une fin de carrière exceptionnelle pour moi. J’avais quarante-quatre ans. C’était mon dernier grand événement."],contexte_historique:["Quelques jours avant mon match, au camp de base des arbitres, à Mexico, il (Sepp Blatter) nous avait demandé de ne pas tolérer le jeu dur, d’être beaucoup plus sévères à l’encontre de ceux qui mettaient en danger l’intégrité physique de leurs adversaires."],vie_equipe:["Les arbitres forment une communauté soudée, très solidaire. À mon retour à l’hôtel, tous sont venus me féliciter de cette décision."],ressentis_emotions:["Je n’ai pas dormi de la nuit. Heureusement, mon frère avait pu venir à Turin. Le savoir dans les tribunes m’avait rassuré. Je jouais gros.","Je crois que c’est le moment où j’ai été le plus malheureux pendant cette Coupe du monde... Ali (Bennaceur) a été montré du doigt à cause d’un acte de tricherie."],grands_moments_sportifs:["Voici presque trente ans que je vis avec cette décision d’exclure José Batista après cinquante et une secondes de jeu. Je ne regrette rien.","Je l’ai vu venir, je l’ai vu venir… Il s’est passé exactement ce que nous, entraîneurs, on déteste."],technique_jeu:[],ethique_justice:["Je devais assumer mes responsabilités jusqu’au bout. Prenez le règlement ! Ce tacle méritait un carton rouge. Le jaune, c’était la solution de facilité...","J’aurais aimé leur répondre qu’un arbitre était là pour protéger les joueurs, et notamment les créateurs."],anecdotes_vie_privee:["Lorsque Yves, l’un de mes jumeaux, qui suit tous mes matches, m’a appelé à mon retour à l’hôtel. Ce carton m’a d’ailleurs coûté cher en communication téléphonique."],preparation_condition_physique:["J’avais du mal, c’est vrai, à boucler mes tests physiques. Ma condition s’était altérée. [...] Je me suis repris en main avec l’aide d’un préparateur."],heritage_posterite:["Paradoxalement, cette réputation d’arbitre qui dégaine ses cartons plus vite que son ombre m’a beaucoup servi par la suite, en Coupe d’Europe notamment."],psychologie_emotion:["Les minutes qui ont suivi le carton rouge ont été très difficiles. Il m’a fallu faire preuve de diplomatie, de pédagogie, de mesure, pour éviter la provocation et ne pas perdre les pédales.","Je ne l’ai pas sorti pour entrer dans le Livre des records ! Sur le coup, je n’ai pas conscience des répercussions de ce carton rouge."]},date_publication:"19/06/2014",resume:"« Je ne l’ai pas sorti pour entrer dans le Livre des records ! » JOËL QUINIOU a expulsé l’Uruguayen Batista au bout de 51 secondes de jeu seulement en 1986.",citation_forte:"La Coupe du monde aux États-Unis représente une fin de carrière exceptionnelle pour moi. J’avais quarante-quatre ans. C’était mon dernier grand événement.",archetypes_ids:["le_supporter","le_stratege","le_patriote"],theme_citations:{parcours_professionnel:"La Coupe du monde aux États-Unis représente une fin de carrière exceptionnelle pour moi. J’avais quarante-quatre ans. C’était mon dernier grand événement.",contexte_historique:"Quelques jours avant mon match, au camp de base des arbitres, à Mexico, il (Sepp Blatter) nous avait demandé de ne pas tolérer le jeu dur, d’être beaucoup plus sévères à l’encontre de ceux qui mettaient en danger l’intégrité physique de leurs adversaires.",vie_equipe:"Les arbitres forment une communauté soudée, très solidaire. À mon retour à l’hôtel, tous sont venus me féliciter de cette décision.",ressentis_emotions:"Je n’ai pas dormi de la nuit. Heureusement, mon frère avait pu venir à Turin. Le savoir dans les tribunes m’avait rassuré. Je jouais gros.",grands_moments_sportifs:"Voici presque trente ans que je vis avec cette décision d’exclure José Batista après cinquante et une secondes de jeu. Je ne regrette rien.",ethique_justice:"Je devais assumer mes responsabilités jusqu’au bout. Prenez le règlement ! Ce tacle méritait un carton rouge. Le jaune, c’était la solution de facilité...",anecdotes_vie_privee:"Lorsque Yves, l’un de mes jumeaux, qui suit tous mes matches, m’a appelé à mon retour à l’hôtel. Ce carton m’a d’ailleurs coûté cher en communication téléphonique.",preparation_condition_physique:"J’avais du mal, c’est vrai, à boucler mes tests physiques. Ma condition s’était altérée. [...] Je me suis repris en main avec l’aide d’un préparateur.",heritage_posterite:"Paradoxalement, cette réputation d’arbitre qui dégaine ses cartons plus vite que son ombre m’a beaucoup servi par la suite, en Coupe d’Europe notamment.",psychologie_emotion:"Les minutes qui ont suivi le carton rouge ont été très difficiles. Il m’a fallu faire preuve de diplomatie, de pédagogie, de mesure, pour éviter la provocation et ne pas perdre les pédales."},joueur:"Joël Quiniou",temps_lecture:"10 min"},{slug:"salvatore-schillaci-1990",index:9,nom:"Salvatore Schillaci",surnom:"Toto",pays:"Italie",mondial:"1990",poste:"Attaquant",image:"/cartes_itw/Schillaci.png",titre_interview:"« C’était comme un conte de fées »",lu:!1,archetype:"Le supporter",archetype_justification:"Il a vécu son Mondial dans la ferveur collective, porté par l'enthousiasme et l'amour immédiat des supporters italiens.",citations:{parcours_professionnel:["Je venais de la Serie B, personne ne me connaissait un an plus tôt. C’était comme un conte de fées.","Mon destin, c’était la Coupe du monde 1990. J’ai peu joué, en Serie A, c’est vrai, mais c’était intense."],contexte_historique:[],vie_equipe:["Pour être honnête, quand on est sur le banc, c’est souvent la même chose : on espère entrer et, du coup, il nous vient de mauvaises pensées. Je les ai eues ce soir-là, moi aussi.","Il m’a dit : “Vas-y, tire-le, au moins tu seras meilleur buteur du tournoi.” Je l’en remercierai toujours."],ressentis_emotions:["Je me retrouve sur le banc à l’Olimpico (à Rome), avec l’hymne national. Je m’en souviendrai toujours. J’avais la chair de poule.","Je suis retourné au vestiaire, j’étais dégoûté. Je suis resté une heure sans bouger, avant de prendre ma douche."],grands_moments_sportifs:["Un centre de Vialli, très tendu, superbe. Devant le but, il y avait les deux Autrichiens, et moi au milieu. J’ai mis toute la force que je pouvais.","Un but chanceux et assez difficile. Ça part de Donadoni, qui frappe la balle, le gardien la repousse et je reprends. [...] je parviens à décaler mon corps et je le prends de la poitrine."],technique_jeu:[],ethique_justice:[],anecdotes_vie_privee:["Après la Coupe du monde, je suis parti en vacances deux semaines sur l’île de Cavallo, en Corse. Là, il y avait le prince Victor-Emmanuel de Savoie. Dès qu’il a su que j’étais là, il a voulu m’inviter chez lui..."],preparation_condition_physique:["J’avais très mal à l’aine. Je voulais tirer (le tir au but en demi-finale), mais je ne le sentais pas avec cette douleur."],heritage_posterite:["Les gens se souviennent de moi partout. Parce qu’un Mondial, même à l’étranger, on se le rappelle. Ça fait tellement plaisir.","Certains mettent dix ans à vivre autant de moments forts. Moi, j’ai tout vécu en une saison."],psychologie_emotion:["Pour un attaquant, les buts sont tellement importants. Quand tu commences à marquer, tu as le moral dans les étoiles et la confiance au maximum.","Encore aujourd’hui, les gens me disent : “Tu me fais le regard halluciné ?“ Mais ce regard, c’était aussi le symbole de mon enthousiasme, de mon envie de gagner."]},date_publication:"20/06/2014",resume:"S’il n’y avait pas eu cette Coupe du monde, on ne serait pas ici à discuter. Le fait de l’avoir jouée et d’avoir atteint ce niveau-là, personnellement, ça me permet aujourd’hui de faire le tour du monde.",citation_forte:"Je venais de la Serie B, personne ne me connaissait un an plus tôt. C’était comme un conte de fées.",archetypes_ids:["l_artiste","le_patriote","le_supporter"],theme_citations:{parcours_professionnel:"Je venais de la Serie B, personne ne me connaissait un an plus tôt. C’était comme un conte de fées.",vie_equipe:"Pour être honnête, quand on est sur le banc, c’est souvent la même chose : on espère entrer et, du coup, il nous vient de mauvaises pensées. Je les ai eues ce soir-là, moi aussi.",ressentis_emotions:"Je me retrouve sur le banc à l’Olimpico (à Rome), avec l’hymne national. Je m’en souviendrai toujours. J’avais la chair de poule.",grands_moments_sportifs:"Un centre de Vialli, très tendu, superbe. Devant le but, il y avait les deux Autrichiens, et moi au milieu. J’ai mis toute la force que je pouvais.",anecdotes_vie_privee:"Après la Coupe du monde, je suis parti en vacances deux semaines sur l’île de Cavallo, en Corse. Là, il y avait le prince Victor-Emmanuel de Savoie. Dès qu’il a su que j’étais là, il a voulu m’inviter chez lui...",preparation_condition_physique:"J’avais très mal à l’aine. Je voulais tirer (le tir au but en demi-finale), mais je ne le sentais pas avec cette douleur.",heritage_posterite:"Les gens se souviennent de moi partout. Parce qu’un Mondial, même à l’étranger, on se le rappelle. Ça fait tellement plaisir.",psychologie_emotion:"Pour un attaquant, les buts sont tellement importants. Quand tu commences à marquer, tu as le moral dans les étoiles et la confiance au maximum.",technique_jeu:"Un but chanceux et assez difficile. Ça part de Donadoni, qui frappe la balle, le gardien la repousse et je reprends. [...] je parviens à décaler mon corps et je le prends de la poitrine."},joueur:"Salvatore Schillaci",temps_lecture:"9 min"},{slug:"michel-platini-1986",index:10,nom:"Michel Platini",surnom:"Platoche",pays:"France",mondial:"1982, 1986",poste:"Milieu offensif",image:"/cartes_itw/Platini.png",titre_interview:"« Je voulais le tirer à ras de terre »",lu:!1,archetype:"Le stratège",archetype_justification:"Pour lui, le football est une partie d'échecs collective où le leader doit articuler le système de jeu.",citations:{parcours_professionnel:["J’ai marqué, ce jour-là, mon dernier but en équipe de France. C’est aussi mon dernier penalty loupé…"],contexte_historique:["À cette époque, le foot français vient de nulle part. Ce n’est pas comme pour la génération 1998, qui s’est appuyée sur 1982 et 1986. Nous, on est partis de rien."],vie_equipe:["C’était une génération au top du top qui n’avait pas besoin qu’on lui parle. Tout le monde savait ce qu’il devait faire.","Après, on rentre au vestiaire et on danse la samba lancée par Jean Tigana. C’est un grand moment."],ressentis_emotions:["Pour moi, la plus grande émotion, c’est Séville. On ne peut pas trouver ça dans un livre, un film ou une scène de la vie. C’est un moment qui te marque à jamais."],grands_moments_sportifs:["Je voulais le tirer à ras de terre et je l’ai mis au-dessus de la barre… Cela fait juste 2,50 m de différence…"],technique_jeu:["Je ne frappe pas la balle, je mets juste mon pied en opposition. Putain, je me suis appliqué. Je ne faisais pas le malin."],ethique_justice:["On est nettement meilleurs, mais ça ne veut pas sourire. [...] Moi, je marque un but valable signalé hors jeu par un arbitre autrichien..."],anecdotes_vie_privee:["Le 21 juin 1975, je suis capitaine de l’équipe de France militaires à l’île Maurice, le jour de mes vingt ans.","Sur les images tournées par Adolphe Dhrey, on me voit avec mon caleçon rose à fleurs. Faut être con pour passer à la télé avec un caleçon rose à fleurs…"],preparation_condition_physique:["Je ne suis pas bien. Je suis blessé. Je boite. Je prends des cachets de Feldène (un anti-inflammatoire) matin, midi et soir depuis deux mois."],heritage_posterite:["Mais c’est marrant, dans ce match, tout le monde se souvient du penalty que j’ai raté et personne du but que j’ai marqué. Car si je ne l’avais pas mis, on n’aurait jamais gagné aux penalties."],psychologie_emotion:["Je me suis “chié” dessus. J’ai eu la trouille de ma vie de louper le but avec mon pied gauche.","On ne joue pas pour être le meilleur joueur du monde, mais pour faire gagner son équipe."]},date_publication:"21/06/2014",resume:"Michel Platini n’a oublié ni son tir au but raté, en quarts de finale de la Coupe du monde 1986, face au Brésil, ni celui réussi par Luis Fernandez, qui qualifia les Bleus pour les demi-finales, le jour de son 31e anniversaire.",citation_forte:"J’ai marqué, ce jour-là, mon dernier but en équipe de France. C’est aussi mon dernier penalty loupé…",archetypes_ids:["l_artiste","le_patriote","le_supporter"],theme_citations:{parcours_professionnel:"J’ai marqué, ce jour-là, mon dernier but en équipe de France. C’est aussi mon dernier penalty loupé…",contexte_historique:"À cette époque, le foot français vient de nulle part. Ce n’est pas comme pour la génération 1998, qui s’est appuyée sur 1982 et 1986. Nous, on est partis de rien.",vie_equipe:"C’était une génération au top du top qui n’avait pas besoin qu’on lui parle. Tout le monde savait ce qu’il devait faire.",ressentis_emotions:"Pour moi, la plus grande émotion, c’est Séville. On ne peut pas trouver ça dans un livre, un film ou une scène de la vie. C’est un moment qui te marque à jamais.",grands_moments_sportifs:"Je voulais le tirer à ras de terre et je l’ai mis au-dessus de la barre… Cela fait juste 2,50 m de différence…",technique_jeu:"Je ne frappe pas la balle, je mets juste mon pied en opposition. Putain, je me suis appliqué. Je ne faisais pas le malin.",ethique_justice:"On est nettement meilleurs, mais ça ne veut pas sourire. [...] Moi, je marque un but valable signalé hors jeu par un arbitre autrichien...",anecdotes_vie_privee:"Le 21 juin 1975, je suis capitaine de l’équipe de France militaires à l’île Maurice, le jour de mes vingt ans.",preparation_condition_physique:"Je ne suis pas bien. Je suis blessé. Je boite. Je prends des cachets de Feldène (un anti-inflammatoire) matin, midi et soir depuis deux mois.",heritage_posterite:"Mais c’est marrant, dans ce match, tout le monde se souvient du penalty que j’ai raté et personne du but que j’ai marqué. Car si je ne l’avais pas mis, on n’aurait jamais gagné aux penalties.",psychologie_emotion:"Je me suis “chié” dessus. J’ai eu la trouille de ma vie de louper le but avec mon pied gauche."},joueur:"Michel Platini",temps_lecture:"10 min"},{slug:"jurgen-sparwasser-1974",index:11,nom:"Jürgen Sparwasser",surnom:null,pays:"RDA",mondial:"1974",poste:"Milieu offensif",image:"/cartes_itw/Sparwasser.png",titre_interview:"« Je ne me suis pas laissé utiliser »",lu:!1,archetype:"Le curieux",archetype_justification:"Son récit mêle trajectoire personnelle singulière (son passage à l'Ouest) et anecdotes sur la propagande en RDA.",citations:{parcours_professionnel:["J’ai joué cinquante-trois matches internationaux, quarante matches de Coupe d’Europe, on est donc allés très souvent dans des pays capitalistes.","J’avais appris le métier de constructeur de machines. On était employés par l’entreprise (SKET), qui comptait douze mille employés, c’est elle qui nous payait, mais on n’a jamais travaillé pour elle."],contexte_historique:["Pourquoi, en 1989, les gens sont descendus dans la rue, à Dresde ou à Leipzig ? Parce qu’ils n’étaient pas contents de la situation et qu’ils auraient préféré nous voir perdre ! C’est aussi simple que ça."],vie_equipe:["Cette équipe était construite autour d’un noyau de joueurs du Dynamo Dresde, du FC Magdebourg et du FC Carl Zeiss Iéna, trois clubs reconnus au niveau international."],ressentis_emotions:["Après le match, quand j’ai remarqué que j’étais le dernier à quitter le terrain. Il y avait toute une grappe de gens qui voulaient quelque chose de moi. Mais je ne comprenais pas vraiment pourquoi je les intéressais tant."],grands_moments_sportifs:["Il y a cette transversale depuis le milieu de terrain et qui arrive dans ma course. Pourquoi ai-je fait cette course et suis-je allé dans cette direction ? Je me le demande encore aujourd’hui."],technique_jeu:["Je me suis un peu trompé pour juger la trajectoire et au lieu de la prendre de la poitrine, je l’ai reçue sur le nez. Mais c’est le destin."],ethique_justice:["Si j’apprenais aujourd’hui que trois ou quatre personnes de cette équipe travaillaient pour la Stasi, je n’irais plus à ce rassemblement. [...] On peut allumer un feu avec mon dossier. Pour moi, c’est passé."],anecdotes_vie_privee:["Vous avez votre valise, un slip et une brosse à dents et vous laissez tous vos copains derrière vous sans savoir si vous les reverrez un jour. Il faut un peu de courage…","Alors qu’elle était enceinte à l’époque, la Stasi l’a interrogée pendant douze heures."],preparation_condition_physique:[],heritage_posterite:["L’homme de la rue, celui qui était devant sa télé ce jour-là et qui s’attendait à ce que l’Allemagne de l’Ouest gagne six ou sept à zéro, il me “réduit” à ce but.","Il y avait une émission le dimanche qui s’appelait Sportschau et ce but est entré au générique. À force, ce n’était pas bon pour moi."],psychologie_emotion:["J’avais joué quarante matches de Coupe d’Europe, pourquoi j’aurais dû faire un complexe ? Je n’avais rien du tout à prouver."]},date_publication:"22/06/2014",resume:"« Je ne me suis pas laissé utiliser » JÜRGEN SPARWASSER, passé à l’Ouest en 1988, se souvient que le régime est-allemand a voulu faire de son but un outil de propagande.",citation_forte:"J’ai joué cinquante-trois matches internationaux, quarante matches de Coupe d’Europe, on est donc allés très souvent dans des pays capitalistes.",archetypes_ids:["le_patriote","le_supporter","le_curieux"],theme_citations:{parcours_professionnel:"J’ai joué cinquante-trois matches internationaux, quarante matches de Coupe d’Europe, on est donc allés très souvent dans des pays capitalistes.",contexte_historique:"Pourquoi, en 1989, les gens sont descendus dans la rue, à Dresde ou à Leipzig ? Parce qu’ils n’étaient pas contents de la situation et qu’ils auraient préféré nous voir perdre ! C’est aussi simple que ça.",vie_equipe:"Cette équipe était construite autour d’un noyau de joueurs du Dynamo Dresde, du FC Magdebourg et du FC Carl Zeiss Iéna, trois clubs reconnus au niveau international.",ressentis_emotions:"Après le match, quand j’ai remarqué que j’étais le dernier à quitter le terrain. Il y avait toute une grappe de gens qui voulaient quelque chose de moi. Mais je ne comprenais pas vraiment pourquoi je les intéressais tant.",grands_moments_sportifs:"Il y a cette transversale depuis le milieu de terrain et qui arrive dans ma course. Pourquoi ai-je fait cette course et suis-je allé dans cette direction ? Je me le demande encore aujourd’hui.",technique_jeu:"Je me suis un peu trompé pour juger la trajectoire et au lieu de la prendre de la poitrine, je l’ai reçue sur le nez. Mais c’est le destin.",ethique_justice:"Si j’apprenais aujourd’hui que trois ou quatre personnes de cette équipe travaillaient pour la Stasi, je n’irais plus à ce rassemblement. [...] On peut allumer un feu avec mon dossier. Pour moi, c’est passé.",anecdotes_vie_privee:"Vous avez votre valise, un slip et une brosse à dents et vous laissez tous vos copains derrière vous sans savoir si vous les reverrez un jour. Il faut un peu de courage…",heritage_posterite:"L’homme de la rue, celui qui était devant sa télé ce jour-là et qui s’attendait à ce que l’Allemagne de l’Ouest gagne six ou sept à zéro, il me “réduit” à ce but.",psychologie_emotion:"J’avais joué quarante matches de Coupe d’Europe, pourquoi j’aurais dû faire un complexe ? Je n’avais rien du tout à prouver."},joueur:"Jürgen Sparwasser",temps_lecture:"9 min"},{slug:"johan-cruyff-1974",index:12,nom:"Johan Cruyff",surnom:"El Flaco",pays:"Pays-Bas",mondial:"1974",poste:"Attaquant",image:"/cartes_itw/Cruyff.png",titre_interview:"« Les seuls perdants dont les gens se souviennent »",lu:!1,archetype:"Le stratège",archetype_justification:"Visionnaire, il a révolutionné le Mondial avec le « football total », basé sur des rotations et une tactique fluide.",citations:{parcours_professionnel:["Nous avions découvert le professionnalisme au milieu des années soixante et je me souviens avoir été le deuxième joueur de mon pays à devenir pro, en 1965."],contexte_historique:["Je suis un enfant de l’après-guerre. Comme les Beatles et beaucoup d’autres. L’époque voulait qu’on lutte plus fort pour faire avancer les choses, les transformer."],vie_equipe:["Il avait le vestiaire totalement sous contrôle. [...] Michels n’aurait jamais accepté. Les règles étaient les mêmes pour tout le monde."],ressentis_emotions:["C’est un match perdu, peut-être la défaite la plus importante de ma vie mais adoucie par cette réflexion : aujourd’hui, quarante ans après [...] Nous sommes les seuls perdants, en quarante ans, dont les gens se souviennent."],grands_moments_sportifs:["C’était la première fois, dans l’histoire d’une Coupe du monde, que le perdant recevait plus d’éloges que le gagnant."],technique_jeu:["On avait inventé un football dans lequel il n’y avait plus de poste fixe, où tout le monde faisait tout. Un attaquant défendait, un défenseur attaquait.","Ils venaient à deux, et même à trois, pour me couper du ballon et de mes partenaires mais, aussitôt, je redescendais au milieu du terrain et un milieu montait me remplacer."],ethique_justice:["Il y a celle du maillot, pendant le Mondial 1974, que j’ai refusé de porter parce que le contrat de l’équipementier, signé au profit de la Fédération, ne prévoyait pas un centime pour les joueurs."],anecdotes_vie_privee:["Mon épouse était allongée par terre, les mains attachées, et moi, il m’avait ligoté à un meuble.","Pendant six mois, les policiers ont dormi à la maison, les policiers ont accompagné les enfants à l’école, des gardes du corps m’ont suivi aux entraînements."],preparation_condition_physique:[],heritage_posterite:["Aujourd’hui, les enfants, les jeunes supporters disent tous que le meilleur du monde s’appelle Messi. Mais leur papa, leur oncle, leur dit : “Non, petit, avant lui, il y a eu celui-là. Regarde.”","Nous avons disputé trois finales et nous les avons perdues toutes les trois : 1974, 1978, 2010. Certains mettent une étoile sur le maillot, nous on a trois places de finaliste. Personne n’a fait mieux que nous."],psychologie_emotion:["La peur n’existait pas dans notre jeu. Jamais nous n’avons parlé d’objectif, de finale, d’enjeu. Personne n’avait pensé que nous en arriverions là.","Une fois en finale, tu atteins ce que j’appelle un sommet. [...] Mais, dans ton subconscient, il se produit un petit relâchement. Pas énorme, 5 %, 10 % peut-être"]},date_publication:"23/06/2014",resume:"« Les seuls perdants dont les gens se souviennent » JOHAN CRUYFF revient sur la défaite de « l’Orange mécanique » face à l’Allemagne de l’Ouest (1-2) en finale de la Coupe du monde 1974.",citation_forte:"Nous avions découvert le professionnalisme au milieu des années soixante et je me souviens avoir été le deuxième joueur de mon pays à devenir pro, en 1965.",archetypes_ids:["le_patriote","le_curieux","le_stratege"],theme_citations:{parcours_professionnel:"Nous avions découvert le professionnalisme au milieu des années soixante et je me souviens avoir été le deuxième joueur de mon pays à devenir pro, en 1965.",contexte_historique:"Je suis un enfant de l’après-guerre. Comme les Beatles et beaucoup d’autres. L’époque voulait qu’on lutte plus fort pour faire avancer les choses, les transformer.",vie_equipe:"Il avait le vestiaire totalement sous contrôle. [...] Michels n’aurait jamais accepté. Les règles étaient les mêmes pour tout le monde.",ressentis_emotions:"C’est un match perdu, peut-être la défaite la plus importante de ma vie mais adoucie par cette réflexion : aujourd’hui, quarante ans après [...] Nous sommes les seuls perdants, en quarante ans, dont les gens se souviennent.",grands_moments_sportifs:"C’était la première fois, dans l’histoire d’une Coupe du monde, que le perdant recevait plus d’éloges que le gagnant.",technique_jeu:"On avait inventé un football dans lequel il n’y avait plus de poste fixe, où tout le monde faisait tout. Un attaquant défendait, un défenseur attaquait.",ethique_justice:"Il y a celle du maillot, pendant le Mondial 1974, que j’ai refusé de porter parce que le contrat de l’équipementier, signé au profit de la Fédération, ne prévoyait pas un centime pour les joueurs.",anecdotes_vie_privee:"Mon épouse était allongée par terre, les mains attachées, et moi, il m’avait ligoté à un meuble.",heritage_posterite:"Aujourd’hui, les enfants, les jeunes supporters disent tous que le meilleur du monde s’appelle Messi. Mais leur papa, leur oncle, leur dit : “Non, petit, avant lui, il y a eu celui-là. Regarde.”",psychologie_emotion:"La peur n’existait pas dans notre jeu. Jamais nous n’avons parlé d’objectif, de finale, d’enjeu. Personne n’avait pensé que nous en arriverions là."},joueur:"Johan Cruyff",temps_lecture:"10 min"},{slug:"antonio-rattin-1966",index:13,nom:"Antonio Rattin",surnom:null,pays:"Argentine",mondial:"1966",poste:"Milieu de terrain",image:"/cartes_itw/Rattin.png",titre_interview:"« L’Angleterre devait gagner ce Mondial »",lu:!1,archetype:"Amoureux du maillot",archetype_justification:"Capitaine emblématique, sa passion pour les couleurs argentines et sa loyauté envers son pays sont au cœur de son récit.",citations:{parcours_professionnel:["J’ai continué à être fidèle à Boca et en 1970, en plein milieu de saison, après un match où j’étais arrivé en retard sur toutes les actions, j’ai décidé que c’était fini.","J’ai monté un cabinet d’assurances, j’ai été député de la nation, président de la commission des sports au Congrès, conseiller municipal de Vicente Lopez..."],contexte_historique:["C’était une autre époque, sans les milliards des droits de télévision et du marketing. Celle où le pays organisateur était soit finaliste, soit champion parce que la FIFA ne vivait que de l’argent des recettes des matches..."],vie_equipe:["Mon rôle était de donner l’exemple, de commander, d’animer. Les autres savaient qu’ils pouvaient compter sur moi."],ressentis_emotions:["Quarante-huit ans après, je n’éprouve aucune fierté en racontant que je me suis assis sur le tapis rouge de la reine ou que j’ai froissé de la main le drapeau anglais. Je l’ai fait inconsciemment."],grands_moments_sportifs:["Je ne vais rien vous apprendre en répétant que ce jour-là, à Wembley, je n’ai commis aucune infraction et même si l’incident s’est transformé en cauchemar, j’ai toujours été en paix avec ma conscience."],technique_jeu:["Je n’étais pas très technique mais, pour un milieu défensif axial, je m’en sortais très bien et je marquais des buts importants, souvent de la tête"],ethique_justice:["Je l’ai fait inconsciemment. Si on veut bien regarder les choses en face, depuis le tirage au sort des arbitres, avancé d’une heure sans nous prévenir pour qu’on n’y soit pas, jusqu’à notre quart de finale, tout était cuisiné d’avance...","Il y a eu complot, je le dis sans hésiter. Le président de la FIFA était un Anglais (Stanley Rous) et l’Angleterre devait gagner ce Mondial..."],anecdotes_vie_privee:["La première fois que j’ai vu un vrai maillot de Boca, je devais avoir six ou sept ans, et je suis tombé amoureux des couleurs.","Je n’ai jamais bu une goutte d’alcool et quand les autres allaient danser, moi j’allais au lit. D’ailleurs, je ne suis jamais allé en discothèque. Je ne pouvais pas."],preparation_condition_physique:["Il me fallait dormir dix heures d’un trait pour être bien sur un terrain."],heritage_posterite:["J’ai su plus tard que j’entrais dans l’histoire puisque aucun autre joueur n’avait été expulsé du vieux Wembley et j’ai été le dernier à l’être sans carton rouge. Mon expulsion a surtout entraîné la création des cartons rouge et jaune au Mondial suivant, en 1970."],psychologie_emotion:["Si je devais résumer mes quinze années de professionnel par un seul mot, je choisirais la sueur. Quand tout se gagne à base d’efforts et de sacrifices, comme ce fut mon cas, on ne peut pas se permettre le moindre écart."]},date_publication:"24/06/2014",resume:"– J’ai horreur de l’injustice, mais l’injustice existe, je l’ai vécue.",citation_forte:"J’ai continué à être fidèle à Boca et en 1970, en plein milieu de saison, après un match où j’étais arrivé en retard sur toutes les actions, j’ai décidé que c’était fini.",archetypes_ids:["l_historien","le_patriote","le_curieux"],theme_citations:{parcours_professionnel:"J’ai continué à être fidèle à Boca et en 1970, en plein milieu de saison, après un match où j’étais arrivé en retard sur toutes les actions, j’ai décidé que c’était fini.",contexte_historique:"C’était une autre époque, sans les milliards des droits de télévision et du marketing. Celle où le pays organisateur était soit finaliste, soit champion parce que la FIFA ne vivait que de l’argent des recettes des matches...",vie_equipe:"Mon rôle était de donner l’exemple, de commander, d’animer. Les autres savaient qu’ils pouvaient compter sur moi.",ressentis_emotions:"Quarante-huit ans après, je n’éprouve aucune fierté en racontant que je me suis assis sur le tapis rouge de la reine ou que j’ai froissé de la main le drapeau anglais. Je l’ai fait inconsciemment.",grands_moments_sportifs:"Je ne vais rien vous apprendre en répétant que ce jour-là, à Wembley, je n’ai commis aucune infraction et même si l’incident s’est transformé en cauchemar, j’ai toujours été en paix avec ma conscience.",technique_jeu:"Je n’étais pas très technique mais, pour un milieu défensif axial, je m’en sortais très bien et je marquais des buts importants, souvent de la tête",ethique_justice:"Je l’ai fait inconsciemment. Si on veut bien regarder les choses en face, depuis le tirage au sort des arbitres, avancé d’une heure sans nous prévenir pour qu’on n’y soit pas, jusqu’à notre quart de finale, tout était cuisiné d’avance...",anecdotes_vie_privee:"La première fois que j’ai vu un vrai maillot de Boca, je devais avoir six ou sept ans, et je suis tombé amoureux des couleurs.",preparation_condition_physique:"Il me fallait dormir dix heures d’un trait pour être bien sur un terrain.",heritage_posterite:"J’ai su plus tard que j’entrais dans l’histoire puisque aucun autre joueur n’avait été expulsé du vieux Wembley et j’ai été le dernier à l’être sans carton rouge. Mon expulsion a surtout entraîné la création des cartons rouge et jaune au Mondial suivant, en 1970.",psychologie_emotion:"Si je devais résumer mes quinze années de professionnel par un seul mot, je choisirais la sueur. Quand tout se gagne à base d’efforts et de sacrifices, comme ce fut mon cas, on ne peut pas se permettre le moindre écart."},joueur:"Antonio Rattin",temps_lecture:"8 min"},{slug:"just-fontaine-1958",index:14,nom:"Just Fontaine",surnom:"Justo",pays:"France",mondial:"1958",poste:"Attaquant",image:"/cartes_itw/Fontaine.png",titre_interview:"« Un jour, en 3050, un archéologue... »",lu:!1,archetype:"L'historien",archetype_justification:"Gardien d'un record légendaire de 13 buts, il incarne la mémoire des grandes épopées du passé.",citations:{parcours_professionnel:["À mon retour en France, alors que je me trouvais en vacances chez mes parents à Cannes, on m’a proposé 250 000 francs, soit mon salaire d’un mois, pour donner le départ du Grand Prix automobile de Reims."],contexte_historique:["Les équipementiers attendaient les quarts de finale pour donner de nouvelles godasses. Comme on ne jouait que sur des terrains gras, je n’avais pas de chaussures de rechange."],vie_equipe:["Entre nous [avec Kopa], ça a été un coup de foudre, mais seulement footballistique. Nous étions dans la même chambre.","Jean Vincent, André Lerond et Yvon Douis m’ont porté en triomphe. (...) Mais ils m’ont vite reposé. Je devais déjà être trop lourd."],ressentis_emotions:["J’avais battu le record de Kocsis mais la France avait perdu en demi-finales contre le Brésil. Il est con ce jeu, mais il est comme ça."],grands_moments_sportifs:["J’ai fini ma Coupe du monde avec treize buts en six matches, dont quatre du droit contre l’Allemagne."],technique_jeu:["Comme je suis droitier mais que j’avais les deux pieds, j’en ai marqué quatre du droit, quatre du gauche et un de la tête.","Ce sport [le basket] m’a appris à faire semblant de regarder d’un côté et à partir de l’autre."],ethique_justice:["C’était lui [Kopa] qui était désigné. Il était donc normal qu’il le tire à 1-1. Je sais qu’aujourd’hui ce serait différent. Mais, à l’époque, ça ne me serait jamais venu à l’idée d’aller lui demander de me le laisser."],anecdotes_vie_privee:["J’ai demandé à Stéphane Bruey, qui avait la même pointure que moi et qui ne jouait pas, de me prêter les siennes. Une fois en quarts, Adidas et Puma nous ont donné d’autres paires.","Récemment, un monsieur a lu dans la Dépêche du Midi que j’avais rencontré ma femme avant un match de Toulouse contre Reims (2-2, le 17 janvier 1960). Elle était allée au stade pour faire plaisir à une amie et elle ne s’en est jamais remise."],preparation_condition_physique:["Le premier facteur, c’est ma blessure au genou droit six mois auparavant. J’ai été opéré du ménisque le 7 décembre, et même si j’ai rejoué très vite, le 15 février, cette blessure m’a permis de souffler durant l’hiver."],heritage_posterite:["Si on m’avait dit qu’il tiendrait pendant au moins cinquante-six ans, je ne l’aurais jamais cru. Je crois même qu’il s’agit d’un des plus vieux records existants dans le sport.","Mais mon record, je l’aurais volontiers échangé contre cinq ou six ans de plus passés à jouer. Ça, c’est sûr."],psychologie_emotion:["Je le connaissais [le record de Kocsis], mais je voulais surtout réussir le meilleur match possible. J’ai été avantagé par le fait que personne ne retient le résultat d’une petite finale, sauf si tu finis troisième."]},date_publication:"25/06/2014",resume:"« Un jour, en 3050, un archéologue... » JUST FONTAINE n’aurait jamais cru que son exploit de 1958 - treize buts en une seule Coupe du monde - resterait inégalé cinquante-six ans plus tard.",citation_forte:"À mon retour en France, alors que je me trouvais en vacances chez mes parents à Cannes, on m’a proposé 250 000 francs, soit mon salaire d’un mois, pour donner le départ du Grand Prix automobile de Reims.",archetypes_ids:["l_historien","le_stratege","le_supporter"],theme_citations:{parcours_professionnel:"À mon retour en France, alors que je me trouvais en vacances chez mes parents à Cannes, on m’a proposé 250 000 francs, soit mon salaire d’un mois, pour donner le départ du Grand Prix automobile de Reims.",contexte_historique:"Les équipementiers attendaient les quarts de finale pour donner de nouvelles godasses. Comme on ne jouait que sur des terrains gras, je n’avais pas de chaussures de rechange.",vie_equipe:"Entre nous [avec Kopa], ça a été un coup de foudre, mais seulement footballistique. Nous étions dans la même chambre.",ressentis_emotions:"J’avais battu le record de Kocsis mais la France avait perdu en demi-finales contre le Brésil. Il est con ce jeu, mais il est comme ça.",grands_moments_sportifs:"J’ai fini ma Coupe du monde avec treize buts en six matches, dont quatre du droit contre l’Allemagne.",technique_jeu:"Comme je suis droitier mais que j’avais les deux pieds, j’en ai marqué quatre du droit, quatre du gauche et un de la tête.",ethique_justice:"C’était lui [Kopa] qui était désigné. Il était donc normal qu’il le tire à 1-1. Je sais qu’aujourd’hui ce serait différent. Mais, à l’époque, ça ne me serait jamais venu à l’idée d’aller lui demander de me le laisser.",anecdotes_vie_privee:"J’ai demandé à Stéphane Bruey, qui avait la même pointure que moi et qui ne jouait pas, de me prêter les siennes. Une fois en quarts, Adidas et Puma nous ont donné d’autres paires.",preparation_condition_physique:"Le premier facteur, c’est ma blessure au genou droit six mois auparavant. J’ai été opéré du ménisque le 7 décembre, et même si j’ai rejoué très vite, le 15 février, cette blessure m’a permis de souffler durant l’hiver.",heritage_posterite:"Si on m’avait dit qu’il tiendrait pendant au moins cinquante-six ans, je ne l’aurais jamais cru. Je crois même qu’il s’agit d’un des plus vieux records existants dans le sport.",psychologie_emotion:"Je le connaissais [le record de Kocsis], mais je voulais surtout réussir le meilleur match possible. J’ai été avantagé par le fait que personne ne retient le résultat d’une petite finale, sauf si tu finis troisième."},joueur:"Just Fontaine",temps_lecture:"9 min"},{slug:"marius-tresor-1978",index:15,nom:"Marius Trésor",surnom:null,pays:"France",mondial:"1978",poste:"Défenseur",image:"/cartes_itw/Trésor.png",titre_interview:"« Les gens ont fait tout un plat de ce truc »",lu:!1,archetype:"Le supporter",archetype_justification:"Il met en avant la solidarité du groupe et l'émotion partagée face aux ambiances électriques des tribunes.",citations:{parcours_professionnel:[],contexte_historique:["À l’époque, Adidas, qui était l’équipementier de l’équipe de France, te faisait signer un contrat personnel à partir de ta troisième sélection.","Il ne faut pas oublier le contexte de l’époque : cela faisait douze ans que l’équipe de France ne s’était plus qualifiée pour une phase finale de Coupe du monde"],vie_equipe:["Comme j’étais leur capitaine, mes équipiers m’ont demandé de faire quelque chose.","Sous l’impulsion de Michel Platini, à qui j’avais cédé le brassard de capitaine, nous avons décidé de partager toutes les primes du Mundial espagnol à venir à parts égales"],ressentis_emotions:["C’était même dégueulasse de la part de journalistes présents sur place de dire que les Italiens nous avaient battus à cause de cette histoire.","Personnellement, et j’insiste, j’ai trouvé toutes ces critiques dégueulasses. On ne pouvait pas dire qu’on avait perdu à cause de cette histoire de chaussures."],grands_moments_sportifs:["L’exemple le plus fameux reste le penalty. Quand je pense que l’arbitre l’a sifflé contre moi !","C’est comme ça que Passarella a ouvert le score juste avant la mi-temps."],technique_jeu:["Luque tire du gauche. Je me jette pour le contrer. Il rate complètement sa frappe qui n’est pas cadrée. La balle me passe entre les jambes avant d’aller taper ma main alors que je me retrouve à terre."],ethique_justice:["Je lui ai alors dit : “Adidas ne veut pas faire d’efforts ? On n’en fera pas non plus.” Et on n’a pas fait les bandes.","Un joueur fait tout pour aller à la Coupe du monde et représenter le mieux possible son pays. En retour, il faut qu’il reçoive quelque chose."],anecdotes_vie_privee:["J’ai beau m’appeler Trésor, je n’ai jamais été bon trésorier. C’est ma femme qui s’occupe de gérer notre argent."],preparation_condition_physique:["Ça ne tombait pas très bien pour moi car je sortais d’une préparation tronquée à cause d’une blessure à la cuisse droite."],heritage_posterite:["C’était tellement petit de mettre notre échec lors de la première Coupe du monde de notre génération sur cette histoire de godasses que cela ne reste pas une blessure pour moi."],psychologie_emotion:["Tu es à la Coupe du monde et tu vas perdre volontairement ? C’était n’importe quoi de penser que nous avions pu faire une connerie pareille !","Il était donc faux de croire qu’on s’était sabordés lors du premier match. Si l’un de mes équipiers en avait eu l’intention, j’aurais été le premier à lui rentrer dedans."]},date_publication:"26/06/2014",resume:"« Les gens ont fait tout un plat de ce truc » MARIUS TRÉSOR, alors capitaine de l’équipe de France, assure que le refus de l’équipementier des Bleus d’augmenter les primes des joueurs n’a joué aucun rôle dans leur élimination au premier...",citation_forte:"À l’époque, Adidas, qui était l’équipementier de l’équipe de France, te faisait signer un contrat personnel à partir de ta troisième sélection.",archetypes_ids:["le_patriote","le_supporter","le_curieux"],theme_citations:{contexte_historique:"À l’époque, Adidas, qui était l’équipementier de l’équipe de France, te faisait signer un contrat personnel à partir de ta troisième sélection.",vie_equipe:"Comme j’étais leur capitaine, mes équipiers m’ont demandé de faire quelque chose.",ressentis_emotions:"C’était même dégueulasse de la part de journalistes présents sur place de dire que les Italiens nous avaient battus à cause de cette histoire.",grands_moments_sportifs:"L’exemple le plus fameux reste le penalty. Quand je pense que l’arbitre l’a sifflé contre moi !",technique_jeu:"Luque tire du gauche. Je me jette pour le contrer. Il rate complètement sa frappe qui n’est pas cadrée. La balle me passe entre les jambes avant d’aller taper ma main alors que je me retrouve à terre.",ethique_justice:"Je lui ai alors dit : “Adidas ne veut pas faire d’efforts ? On n’en fera pas non plus.” Et on n’a pas fait les bandes.",anecdotes_vie_privee:"J’ai beau m’appeler Trésor, je n’ai jamais été bon trésorier. C’est ma femme qui s’occupe de gérer notre argent.",preparation_condition_physique:"Ça ne tombait pas très bien pour moi car je sortais d’une préparation tronquée à cause d’une blessure à la cuisse droite.",heritage_posterite:"C’était tellement petit de mettre notre échec lors de la première Coupe du monde de notre génération sur cette histoire de godasses que cela ne reste pas une blessure pour moi.",psychologie_emotion:"Tu es à la Coupe du monde et tu vas perdre volontairement ? C’était n’importe quoi de penser que nous avions pu faire une connerie pareille !"},joueur:"Marius Trésor",temps_lecture:"9 min"},{slug:"mwepu-ilunga-1974",index:16,nom:"Mwepu Ilunga",surnom:null,pays:"Zaïre",mondial:"1974",poste:"Défenseur",image:"/cartes_itw/Ilunga.png",titre_interview:"« On nous a dit de jouer, sinon nous irions au cachot »",lu:!1,archetype:"Le curieux",archetype_justification:"Son témoignage dévoile les dessous sombres et les pressions politiques subies par le Zaïre en 1974.",citations:{parcours_professionnel:["J’ai continué au Tout Puissant Mazembe, pendant encore six années.","Je fais aussi partie du staff de l’équipe seniors des Léopards, où je m’occupe de la discipline. Je suis resté dans le football, c’est ça, ma vie."],contexte_historique:["À l’époque, il était très dur de se qualifier. Il n’y avait qu’un pays africain qui allait à la Coupe du monde (contre 5 aujourd’hui).","Jusqu’à trente ans, nous n’avions pas le droit d’aller jouer ailleurs."],vie_equipe:["Nous étions très mécontents. Nous venions de passer deux mois loin de nos familles, sans personne à nos côtés.","Le match est très mal passé auprès de nos dirigeants. Nous avons été enfermés dans notre hôtel. Des gens ont été envoyés pour nous surveiller"],ressentis_emotions:["Je ne peux pas dire autre chose qu’un mauvais souvenir : nous avons tout perdu.","Quand on est partis à la Coupe du monde, il y avait des gens partout pour nous encourager et nous dire au revoir. Au retour, à Kinshasa, il n’y avait plus personne."],grands_moments_sportifs:["Et ce match-là, nous ne le perdons que 2-0 ! Nous étions contents ! Nous avions bien joué !"],technique_jeu:["Normalement, quand vous défendez, vous suivez le porteur du ballon. Regardez le match, nous ne l’avons pas fait. Nous marchions sur le terrain. Au bout de trente minutes, il y avait déjà 5-0."],ethique_justice:["On a détourné notre argent ! Nous ne pouvions pas faire comme si rien ne s’était passé.","J’ai voulu qu’il me donne un carton rouge. Je me suis dit :  ‘’Je ne joue plus. Pourquoi je resterais sur le terrain à prendre le risque de ne pas rentrer chez moi alors que les autres, ceux qui ont pris notre argent, nous regardent tranquillement en tribune ?’’"],anecdotes_vie_privee:["Il y avait une délégation à part, des féticheurs venus de tout le pays et qui avaient été sélectionnés pour aider l’équipe."],preparation_condition_physique:["À cette période, le sélectionneur nous avait imposés pendant un mois trois entraînements par jour : 10 heures, 13 h 30, 18 heures."],heritage_posterite:["Nous ne pensions pas revenir riches de la Coupe du monde, mais tout le monde pensait que notre situation allait changer. Or nous vivons comme des mendiants."],psychologie_emotion:["Deux heures avant le coup d’envoi, nous ne voulions toujours pas jouer. Et puis il y a eu des menaces. On nous a dit de jouer, sinon nous irions au cachot. Donc nous sommes allés sur le terrain, mais nous avons saboté le match.","J’étais énervé par ce qu’ils nous disaient. En même temps, c’est aussi une occasion que j’ai saisie pour provoquer l’arbitre."]},date_publication:"27/06/2014",resume:"ses côtés, dans la sélection du Zaïre, évoluaient des papas célèbres. Ricky Mavuba, le père de l’international français Rio, ou Jean Kembo Uba Kembo, celui de l’ancien Rennais Jirès Kembo.",citation_forte:"J’ai continué au Tout Puissant Mazembe, pendant encore six années.",archetypes_ids:["l_historien","le_patriote","le_curieux"],theme_citations:{parcours_professionnel:"J’ai continué au Tout Puissant Mazembe, pendant encore six années.",contexte_historique:"À l’époque, il était très dur de se qualifier. Il n’y avait qu’un pays africain qui allait à la Coupe du monde (contre 5 aujourd’hui).",vie_equipe:"Nous étions très mécontents. Nous venions de passer deux mois loin de nos familles, sans personne à nos côtés.",ressentis_emotions:"Je ne peux pas dire autre chose qu’un mauvais souvenir : nous avons tout perdu.",grands_moments_sportifs:"Et ce match-là, nous ne le perdons que 2-0 ! Nous étions contents ! Nous avions bien joué !",technique_jeu:"Normalement, quand vous défendez, vous suivez le porteur du ballon. Regardez le match, nous ne l’avons pas fait. Nous marchions sur le terrain. Au bout de trente minutes, il y avait déjà 5-0.",ethique_justice:"On a détourné notre argent ! Nous ne pouvions pas faire comme si rien ne s’était passé.",anecdotes_vie_privee:"Il y avait une délégation à part, des féticheurs venus de tout le pays et qui avaient été sélectionnés pour aider l’équipe.",preparation_condition_physique:"À cette période, le sélectionneur nous avait imposés pendant un mois trois entraînements par jour : 10 heures, 13 h 30, 18 heures.",heritage_posterite:"Nous ne pensions pas revenir riches de la Coupe du monde, mais tout le monde pensait que notre situation allait changer. Or nous vivons comme des mendiants.",psychologie_emotion:"Deux heures avant le coup d’envoi, nous ne voulions toujours pas jouer. Et puis il y a eu des menaces. On nous a dit de jouer, sinon nous irions au cachot. Donc nous sommes allés sur le terrain, mais nous avons saboté le match."},joueur:"Mwepu Ilunga",temps_lecture:"7 min"},{slug:"oleg-salenko-1994",index:17,nom:"Oleg Salenko",surnom:null,pays:"Russie",mondial:"1994",poste:"Attaquant",image:"/cartes_itw/Salenko.png",titre_interview:"« Mes buts n’ont servi à rien »",lu:!1,archetype:"L'historien",archetype_justification:"Son quintuplé s'inscrit dans la mémoire d'une période de transition historique pour le football russe.",citations:{parcours_professionnel:["Je me suis retrouvé sans travail, sans argent et sans club deux ans avant la World Cup.","Après une tentative ratée à Karlsruhe, en Allemagne, j’ai appris que le CD Logrones cherchait un attaquant. J’y suis allé."],contexte_historique:["À mes débuts, l’équipe d’URSS était composée de joueurs venant de toutes les républiques soviétiques, surtout de la Géorgie et de l’Ukraine, comme moi.","Mais, après la fin de l’URSS (le 26 décembre 1991), les responsables de la naissante Fédération de football d’Ukraine (FFU) ont convoqué les joueurs sélectionnables, dont moi."],vie_equipe:["Dimitri était mon pote.","Chaque entraîneur avait ses chouchous."],ressentis_emotions:["Mes buts n’ont servi à rien. J’aurais préféré en marquer un dans cinq matches décisifs plutôt que cinq dans une rencontre qui nous a éliminés."],grands_moments_sportifs:["Je crois que, ce jour-là, j’ai marqué cinq buts dans un match de Coupe du monde.","J’étais tellement content que j’ai échangé mon maillot avec un Français après le coup de sifflet final. Résultat : je me suis fait virer de la sélection."],technique_jeu:["Sur le terrain, quatre de mes cinq buts contre le Cameroun ont été le résultat d’une passe à une touche de balle alors que, d’habitude, je préférais dribbler l’adversaire en tête-à-tête."],ethique_justice:["Nous avions alors adressé une lettre à nos dirigeants les menaçant de refuser de participer à cette Coupe du monde s’ils ne nous laissaient pas choisir nos chaussures."],anecdotes_vie_privee:["Cette nuit, j’ai rêvé que je marquais cinq buts et qu’on allait en finale.","Je ne suis ni superstitieux ni fétichiste. Je n’accordais pas beaucoup d’importance à ces choses-là."],preparation_condition_physique:["Le dernier stage à Novogorsk avait confirmé mes sensations : je me sentais en super forme."],heritage_posterite:["En fait, mes cinq buts ont surtout marqué ma vie après ma carrière. Cet exploit me sert encore tous les jours.","Celui-là, de record, il ne sera jamais battu."],psychologie_emotion:["Je jouais et je marquais sans réfléchir, ni en avoir marre. Même après mon cinquième but, je ne me suis pas dit : ouaaaah ! Oleg, tu viens de marquer cinq buts dans un match de Coupe du monde.","Je savais que les quatre derniers meilleurs buteurs de la Coupe du monde l’avaient été avec six buts. Je me suis donc dit : ça y est. Tu y es."]},date_publication:"28/06/2014",resume:"une heure, cinq buts Qualifiée pour sa première phase finale, la Russie, qui a succédé à l’URSS, fait figure d’outsider au début de la World Cup nord-américaine.",citation_forte:"Je me suis retrouvé sans travail, sans argent et sans club deux ans avant la World Cup.",archetypes_ids:["l_historien","le_curieux","le_stratege"],theme_citations:{parcours_professionnel:"Je me suis retrouvé sans travail, sans argent et sans club deux ans avant la World Cup.",contexte_historique:"À mes débuts, l’équipe d’URSS était composée de joueurs venant de toutes les républiques soviétiques, surtout de la Géorgie et de l’Ukraine, comme moi.",vie_equipe:"Dimitri était mon pote.",ressentis_emotions:"Mes buts n’ont servi à rien. J’aurais préféré en marquer un dans cinq matches décisifs plutôt que cinq dans une rencontre qui nous a éliminés.",grands_moments_sportifs:"Je crois que, ce jour-là, j’ai marqué cinq buts dans un match de Coupe du monde.",technique_jeu:"Sur le terrain, quatre de mes cinq buts contre le Cameroun ont été le résultat d’une passe à une touche de balle alors que, d’habitude, je préférais dribbler l’adversaire en tête-à-tête.",ethique_justice:"Nous avions alors adressé une lettre à nos dirigeants les menaçant de refuser de participer à cette Coupe du monde s’ils ne nous laissaient pas choisir nos chaussures.",anecdotes_vie_privee:"Cette nuit, j’ai rêvé que je marquais cinq buts et qu’on allait en finale.",preparation_condition_physique:"Le dernier stage à Novogorsk avait confirmé mes sensations : je me sentais en super forme.",heritage_posterite:"En fait, mes cinq buts ont surtout marqué ma vie après ma carrière. Cet exploit me sert encore tous les jours.",psychologie_emotion:"Je jouais et je marquais sans réfléchir, ni en avoir marre. Même après mon cinquième but, je ne me suis pas dit : ouaaaah ! Oleg, tu viens de marquer cinq buts dans un match de Coupe du monde."},joueur:"Oleg Salenko",temps_lecture:"9 min"},{slug:"claudio-gentile-1982",index:18,nom:"Claudio Gentile",surnom:null,pays:"Italie",mondial:"1982",poste:"Défenseur",image:"/cartes_itw/Gentile.png",titre_interview:"« Il me traitait de tous les noms »",lu:!1,archetype:"Le stratège",archetype_justification:"Il a fait du marquage individuel une science tactique, étudiant minutieusement chaque déplacement de ses adversaires.",citations:{parcours_professionnel:["J’ai fait 500 matches et je n’ai jamais été expulsé pour jeu dangereux de toute ma carrière ! J’ai gagné six scudetti, deux Coupes d’Europe…"],contexte_historique:["On est partis d’Italie dans un scepticisme terrible. Tout le monde critiquait Enzo Bearzot, parce qu’il n’avait pas appelé certains joueurs. Il y avait aussi eu le scandale du Totonero."],vie_equipe:["On était hyper soudés, on se sacrifiait les uns pour les autres. Aujourd’hui, on ne verrait plus ça. La force, c’était d’avoir les coéquipiers qui pensaient comme toi."],ressentis_emotions:["J’ai beaucoup gagné, mais une Coupe du monde, c’est le top.","Ce n’est pas beau d’être élu troisième ou quatrième joueur le plus méchant de tous les temps."],grands_moments_sportifs:["Le match historique, dont on se souvient tous comme d’un résultat fabuleux, c’est la victoire contre le Brésil (3-2).","Nous, on a gagné une Coupe du monde en battant tous les meilleurs. L’Argentine, le Brésil, la Pologne, l’Allemagne. Ça donne une saveur particulière à ce trophée."],technique_jeu:["Quand il se retourne, s’il vient vers toi, tu ne l’arrêtes plus. Il va trop vite. Alors je me suis dit : “Je vais être toujours collé à son derrière.”","Nous, dans les années 1970-1980, on était considérés comme les meilleurs défenseurs au monde parce qu’on était très bons dans le marquage individuel."],ethique_justice:["Je n’ai jamais blessé personne ! Ceux qui connaissent le foot savent que ce n’est pas vrai.","Si j’avais été un mauvais, un méchant, j’aurais été expulsé un jour ou l’autre, non ?"],anecdotes_vie_privee:[],preparation_condition_physique:["Quand tu fais un match tous les deux jours, tu n’as pas le temps de prévoir des schémas, de travailler en profondeur. Mais on était prêts."],heritage_posterite:["Parfois, on colle des étiquettes aux gens alors qu’ils ne les méritent pas. Moi, j’étais le gros dur. Ça ne me fait pas plaisir, évidemment.","On ne se souvient pas si tu étais offensif ou défensif, on se souvient que tu as gagné."],psychologie_emotion:["Je n’ai jamais eu peur de ma carrière. Une fois que je suis face à l’adversaire, Maradona ou un autre, je n’ai pas peur. C’est un duel d’hommes, rien d’autre.","Moi, je joue au foot et le foot, c’est fait pour les hommes, pas pour les demoiselles. Sinon, tu fais de la danse."]},date_publication:"29/06/2014",resume:"un autre football, une autre manière de défendre. Un marquage individuel, avec l’attaquant serré de près.",citation_forte:"J’ai fait 500 matches et je n’ai jamais été expulsé pour jeu dangereux de toute ma carrière ! J’ai gagné six scudetti, deux Coupes d’Europe…",archetypes_ids:["l_historien","le_supporter"],theme_citations:{parcours_professionnel:"J’ai fait 500 matches et je n’ai jamais été expulsé pour jeu dangereux de toute ma carrière ! J’ai gagné six scudetti, deux Coupes d’Europe…",contexte_historique:"On est partis d’Italie dans un scepticisme terrible. Tout le monde critiquait Enzo Bearzot, parce qu’il n’avait pas appelé certains joueurs. Il y avait aussi eu le scandale du Totonero.",vie_equipe:"On était hyper soudés, on se sacrifiait les uns pour les autres. Aujourd’hui, on ne verrait plus ça. La force, c’était d’avoir les coéquipiers qui pensaient comme toi.",ressentis_emotions:"J’ai beaucoup gagné, mais une Coupe du monde, c’est le top.",grands_moments_sportifs:"Le match historique, dont on se souvient tous comme d’un résultat fabuleux, c’est la victoire contre le Brésil (3-2).",technique_jeu:"Quand il se retourne, s’il vient vers toi, tu ne l’arrêtes plus. Il va trop vite. Alors je me suis dit : “Je vais être toujours collé à son derrière.”",ethique_justice:"Je n’ai jamais blessé personne ! Ceux qui connaissent le foot savent que ce n’est pas vrai.",preparation_condition_physique:"Quand tu fais un match tous les deux jours, tu n’as pas le temps de prévoir des schémas, de travailler en profondeur. Mais on était prêts.",heritage_posterite:"Parfois, on colle des étiquettes aux gens alors qu’ils ne les méritent pas. Moi, j’étais le gros dur. Ça ne me fait pas plaisir, évidemment.",psychologie_emotion:"Je n’ai jamais eu peur de ma carrière. Une fois que je suis face à l’adversaire, Maradona ou un autre, je n’ai pas peur. C’est un duel d’hommes, rien d’autre."},joueur:"Claudio Gentile",temps_lecture:"10 min"},{slug:"michel-hidalgo-1982",index:19,nom:"Michel Hidalgo",surnom:null,pays:"France",mondial:"1982",poste:"Sélectionneur",image:"/cartes_itw/Hidalgo.png",titre_interview:"« L’émir était un type délicieux »",lu:!1,archetype:"Le stratège",archetype_justification:"Architecte du « carré magique », il privilégiait la construction tactique et la maîtrise technique collective.",citations:{parcours_professionnel:["J’ai fait une connerie : Barcelone en 1985. Les dirigeants du Barça m’ont appelé. (...) Je pensais avoir besoin de respirer. Résultat, j’ai signé à Marseille un an après."],contexte_historique:["Les photographes et les cameramen s’étaient agglutinés pour suivre cette scène quand même incroyable. Résultat, dans la cohue, je prends une caméra en pleine gueule. Et à l’époque, croyez-moi, elles étaient loin d’être légères.","Le problème des joueurs, c’était d’être titulaires. Ils étaient vingt-deux dans le groupe, mais les onze remplaçants n’étaient pas tous sur le banc comme maintenant."],vie_equipe:["Cette équipe, ce n’était que du plaisir.","C’est vrai, je les aimais, mes joueurs. Mais il faut aimer ses joueurs. Nous étions relativement liés."],ressentis_emotions:["La réponse disproportionnée des policiers m’a scandalisé. Ils l’ont quand même menotté.","C’est la plus grande déception de ma carrière évidemment."],grands_moments_sportifs:["Tout y est dans ce match. La qualité du jeu. On a joué notre jeu. Il y a l’injustice et l’arbitre qui ne sanctionne pas Schumacher pour son agression sur Battiston."],technique_jeu:["Avec Tigana et Genghini, nous n’avions pas un milieu très défensif. Je partais du principe que quatre défenseurs pour bloquer les deux attaquants adverses, cela suffisait."],ethique_justice:["Je suis allé voir le directeur du stade et je lui ai dit que si ce jeune n’était pas relâché au coup d’envoi, alors mon équipe n’entrerait pas sur la pelouse et nous expliquerions au monde entier pourquoi.","Franchement, ce n’est pas l’attitude de l’émir qui m’a choqué. Ce qui m’a dérangé, c’est qu’on le laisse descendre de la tribune et entrer sur le terrain pour parlementer avec ses joueurs. L’arbitre n’aurait jamais dû accepter ça."],anecdotes_vie_privee:["C’était un type délicieux (l'émir). Il a été tué pendant la guerre du Golfe en aidant son frère, le roi, à prendre la fuite à bord d’un hélicoptère. Quand je suis retourné au Koweït, j’ai voulu aller me recueillir sur sa tombe."],preparation_condition_physique:["Nous avions préparé la compétition à Font-Romeu, où il faisait beau mais relativement frais. À Bilbao, nous nous sommes retrouvés dans un four. Une vraie canicule. Les Anglais s’y étaient mieux préparés."],heritage_posterite:["Pourtant, deux ans après, on a décroché l’Euro, le premier titre du football français. On pourrait penser que c’est une forme de réconfort, de satisfaction qui efface Séville. Pas du tout."],psychologie_emotion:["Favoriser un climat positif au sein d’un collectif, ce n’est pas facile. Ça dépend des résultats.","J’avais des lions sur le terrain, des enfants dans le vestiaire. Ils pleuraient, en voulaient à tout le monde."]},date_publication:"30/06/2014",resume:"Un coup de sifflet, une colère noire La scène occupe forcément les souvenirs de tous les plus de quarante ans qui aimaient déjà le foot, enfant.",citation_forte:"J’ai fait une connerie : Barcelone en 1985. Les dirigeants du Barça m’ont appelé. (...) Je pensais avoir besoin de respirer. Résultat, j’ai signé à Marseille un an après.",archetypes_ids:["le_patriote","le_stratege","le_supporter"],theme_citations:{parcours_professionnel:"J’ai fait une connerie : Barcelone en 1985. Les dirigeants du Barça m’ont appelé. (...) Je pensais avoir besoin de respirer. Résultat, j’ai signé à Marseille un an après.",contexte_historique:"Les photographes et les cameramen s’étaient agglutinés pour suivre cette scène quand même incroyable. Résultat, dans la cohue, je prends une caméra en pleine gueule. Et à l’époque, croyez-moi, elles étaient loin d’être légères.",vie_equipe:"Cette équipe, ce n’était que du plaisir.",ressentis_emotions:"La réponse disproportionnée des policiers m’a scandalisé. Ils l’ont quand même menotté.",grands_moments_sportifs:"Tout y est dans ce match. La qualité du jeu. On a joué notre jeu. Il y a l’injustice et l’arbitre qui ne sanctionne pas Schumacher pour son agression sur Battiston.",technique_jeu:"Avec Tigana et Genghini, nous n’avions pas un milieu très défensif. Je partais du principe que quatre défenseurs pour bloquer les deux attaquants adverses, cela suffisait.",ethique_justice:"Je suis allé voir le directeur du stade et je lui ai dit que si ce jeune n’était pas relâché au coup d’envoi, alors mon équipe n’entrerait pas sur la pelouse et nous expliquerions au monde entier pourquoi.",anecdotes_vie_privee:"C’était un type délicieux (l'émir). Il a été tué pendant la guerre du Golfe en aidant son frère, le roi, à prendre la fuite à bord d’un hélicoptère. Quand je suis retourné au Koweït, j’ai voulu aller me recueillir sur sa tombe.",preparation_condition_physique:"Nous avions préparé la compétition à Font-Romeu, où il faisait beau mais relativement frais. À Bilbao, nous nous sommes retrouvés dans un four. Une vraie canicule. Les Anglais s’y étaient mieux préparés.",heritage_posterite:"Pourtant, deux ans après, on a décroché l’Euro, le premier titre du football français. On pourrait penser que c’est une forme de réconfort, de satisfaction qui efface Séville. Pas du tout.",psychologie_emotion:"Favoriser un climat positif au sein d’un collectif, ce n’est pas facile. Ça dépend des résultats."},joueur:"Michel Hidalgo",temps_lecture:"10 min"},{slug:"ramon-quiroga-1978",index:20,nom:"Ramon Quiroga",surnom:null,pays:"Pérou",mondial:"1978",poste:"Gardien",image:"/cartes_itw/Quiroga.png",titre_interview:"« On a perdu, point final »",lu:!1,archetype:"Le curieux",archetype_justification:"Son parcours de naturalisé au cœur d'une dictature argentine offre une perspective fascinante sur les coulisses du Mondial 1978.",citations:{parcours_professionnel:["Je suis joueur professionnel dans le club de mes débuts, à Rosario Central, quand je reçois une offre de Cristal, une équipe péruvienne (de Lima) avec de gros moyens, et je ne la laisse pas passer.","Ma dernière saison, je l’ai faite sous le maillot d’Universitario de Deportes, en 1986, et tout de suite après, pour accéder au souhait de mon président, je suis devenu entraîneur."],contexte_historique:["Dans le pays, hormis ceux qui étaient engagés directement dans la lutte contre le régime de Videla, il était difficile de se rendre compte de ce qui se passait."],vie_equipe:["C’est exact, il y avait des jalousies entre nous. À Cristal, on devait être une bonne dizaine de sélectionnés pour cette Coupe du monde, il n’y avait jamais de problème de salaire."],ressentis_emotions:["J’ai passé une sale soirée et je ne pourrai jamais l’oublier mais, au cours de ces quatre-vingt-dix minutes, j’en ai aussi arrêté beaucoup d’autres qui auraient pu donner au score une allure scandaleuse.","Nous n’avons jamais pu prendre notre revanche, et cette brûlure d’amour-propre, même si elle s’est estompée avec le temps, ne s’effacera jamais."],grands_moments_sportifs:["Ce que je sais, c’est que, sur les six buts, ils en ont marqué deux, par Tarantini (le deuxième, 43e) et Luque (le troisième, 50e) en position de hors-jeu."],technique_jeu:[],ethique_justice:["Je n’ai jamais été traumatisé par ce 6-0 pour la bonne raison que je ne me suis pas couché.","Si je m’étais couché, comme certains de mes coéquipiers, ce soir-là, je n’aurais pas disputé d’autres matches sous ce maillot."],anecdotes_vie_privee:["J’ai reçu une enveloppe avec 1 500 dollars. Moi qui étais un des joueurs les plus en vue, j’ai touché 1 500 dollars ! J’en ai laissé 1 000 à ma mère pour sa maison, à Rosario.","Un jour, à Lima, des terroristes, venus piéger une voiture (...) ont semé des mines antipersonnel jusque sur notre terrain de foot."],preparation_condition_physique:["Je m’isolais avant chaque match, c’était ma façon de me concentrer. Je trouvais toujours un endroit, une salle où m’échauffer, à l’écart de tout le monde"],heritage_posterite:["Cela fait trente-cinq ans que je vois des journalistes de tous les pays venir m’interroger sur cet Argentine-Pérou du 21 juin 1978. Et ils finissent tous par me demander si, ce jour-là, je me suis couché"],psychologie_emotion:["Solide mentalement. Ç’a toujours été ma force de ne pas douter. Chez un gardien, le caractère, c’est capital, et moi j’en ai beaucoup."]},date_publication:"01/07/2014",resume:"Le 6-0 de la polémique Ce 21 juin 1978, avant le dernier match du groupe B de ce second tour, l’Argentine et le Brésil sont à égalité. Le premier ira en finale.",citation_forte:"Je suis joueur professionnel dans le club de mes débuts, à Rosario Central, quand je reçois une offre de Cristal, une équipe péruvienne (de Lima) avec de gros moyens, et je ne la laisse pas passer.",archetypes_ids:["le_patriote","le_curieux","le_supporter"],theme_citations:{parcours_professionnel:"Je suis joueur professionnel dans le club de mes débuts, à Rosario Central, quand je reçois une offre de Cristal, une équipe péruvienne (de Lima) avec de gros moyens, et je ne la laisse pas passer.",contexte_historique:"Dans le pays, hormis ceux qui étaient engagés directement dans la lutte contre le régime de Videla, il était difficile de se rendre compte de ce qui se passait.",vie_equipe:"C’est exact, il y avait des jalousies entre nous. À Cristal, on devait être une bonne dizaine de sélectionnés pour cette Coupe du monde, il n’y avait jamais de problème de salaire.",ressentis_emotions:"J’ai passé une sale soirée et je ne pourrai jamais l’oublier mais, au cours de ces quatre-vingt-dix minutes, j’en ai aussi arrêté beaucoup d’autres qui auraient pu donner au score une allure scandaleuse.",grands_moments_sportifs:"Ce que je sais, c’est que, sur les six buts, ils en ont marqué deux, par Tarantini (le deuxième, 43e) et Luque (le troisième, 50e) en position de hors-jeu.",ethique_justice:"Je n’ai jamais été traumatisé par ce 6-0 pour la bonne raison que je ne me suis pas couché.",anecdotes_vie_privee:"J’ai reçu une enveloppe avec 1 500 dollars. Moi qui étais un des joueurs les plus en vue, j’ai touché 1 500 dollars ! J’en ai laissé 1 000 à ma mère pour sa maison, à Rosario.",preparation_condition_physique:"Je m’isolais avant chaque match, c’était ma façon de me concentrer. Je trouvais toujours un endroit, une salle où m’échauffer, à l’écart de tout le monde",heritage_posterite:"Cela fait trente-cinq ans que je vois des journalistes de tous les pays venir m’interroger sur cet Argentine-Pérou du 21 juin 1978. Et ils finissent tous par me demander si, ce jour-là, je me suis couché",psychologie_emotion:"Solide mentalement. Ç’a toujours été ma force de ne pas douter. Chez un gardien, le caractère, c’est capital, et moi j’en ai beaucoup."},joueur:"Ramon Quiroga",temps_lecture:"8 min"},{slug:"khalilou-fadiga-2002",index:21,nom:"Khalilou Fadiga",surnom:"Khali",pays:"Sénégal",mondial:"2002",poste:"Milieu de terrain",image:"/cartes_itw/Fadiga.png",titre_interview:"« Je n’ai pas oublié le mépris »",lu:!1,archetype:"Amoureux du maillot",archetype_justification:"Il souligne la fierté immense de porter le maillot sénégalais et le désir de faire taire le mépris envers sa nation.",citations:{parcours_professionnel:["J’avais trouvé un accord avec l’Inter (Milan) avant la Coupe du monde. J’avais donné ma parole pour l’année d’après et c’est ce qui s’est fait"],contexte_historique:["Vous vous rendez compte ? Une ancienne colonie française, une équipe dont tous les joueurs évoluent dans le Championnat français et tu joues contre ces gens-là ?"],vie_equipe:["Quand on était en dehors du terrain, Bruno Metsu nous laissait être des humains. C’était notre capitaine, notre ami. Mais quand on était sur la pelouse, c’était lui le patron.","Avec tous les caractères qu’il y avait, c’était explosif. Parfois, ça a été très chaud. Certains ont plusieurs fois failli en venir aux mains."],ressentis_emotions:["Personnellement, je dois dire que je n’ai pas oublié le mépris dont on avait fait l’objet à l’époque.","Mais il y avait de la joie, bien sûr, une joie indescriptible. La plupart d’entre nous avions décidé de jouer pour le Sénégal. C’était un vrai choix"],grands_moments_sportifs:["C’est ça, le plus beau : on n’a pas besoin de vidéos, de livres ou d’écrits. C’est gravé dans la tête, gravé dans le cœur et ça, on ne peut pas l’enlever."],technique_jeu:["On était des guerriers. Ceux qui n’étaient pas des techniciens compensaient par leur cœur."],ethique_justice:["Vous savez, cette histoire, c’était vraiment une connerie, un pari stupide avec les copains. (...) Je me suis dénoncé, j’ai rendu le truc et l’affaire était réglée. Une heure après le vol !"],anecdotes_vie_privee:["Et puis nous, à la Coupe du monde, on était avec femme et enfants. On allait sortir ?"],preparation_condition_physique:["On arrive devant cet internat, le prototype d’un internat d’étudiants et là, on dit stop. On fait une réunion dans le jardin. On refuse d’entrer là-dedans."],heritage_posterite:["Et si on m’avait donné le choix entre un quart de finale de Coupe du monde et une Coupe d’Afrique, j’aurais choisi la CAN. J’aurais tellement aimé en gagner une."],psychologie_emotion:["Jamais je n’ai vu cette équipe sous pression, jamais. Et c’est pour cela, à cause de notre attitude, qui pouvait paraître prétentieuse parfois, que certains disaient qu’on était des branleurs."]},date_publication:"02/07/2014",resume:"Le 31 mai 2002, en match d’ouverture de la Coupe du monde coorganisée par le Japon et la Corée du Sud, le Sénégal s’imposait face à la France (1-0), championne du monde et d’Europe en titre.",citation_forte:"J’avais trouvé un accord avec l’Inter (Milan) avant la Coupe du monde. J’avais donné ma parole pour l’année d’après et c’est ce qui s’est fait",archetypes_ids:["le_patriote","le_supporter","le_curieux"],theme_citations:{parcours_professionnel:"J’avais trouvé un accord avec l’Inter (Milan) avant la Coupe du monde. J’avais donné ma parole pour l’année d’après et c’est ce qui s’est fait",contexte_historique:"Vous vous rendez compte ? Une ancienne colonie française, une équipe dont tous les joueurs évoluent dans le Championnat français et tu joues contre ces gens-là ?",vie_equipe:"Quand on était en dehors du terrain, Bruno Metsu nous laissait être des humains. C’était notre capitaine, notre ami. Mais quand on était sur la pelouse, c’était lui le patron.",ressentis_emotions:"Personnellement, je dois dire que je n’ai pas oublié le mépris dont on avait fait l’objet à l’époque.",grands_moments_sportifs:"C’est ça, le plus beau : on n’a pas besoin de vidéos, de livres ou d’écrits. C’est gravé dans la tête, gravé dans le cœur et ça, on ne peut pas l’enlever.",technique_jeu:"On était des guerriers. Ceux qui n’étaient pas des techniciens compensaient par leur cœur.",ethique_justice:"Vous savez, cette histoire, c’était vraiment une connerie, un pari stupide avec les copains. (...) Je me suis dénoncé, j’ai rendu le truc et l’affaire était réglée. Une heure après le vol !",anecdotes_vie_privee:"Et puis nous, à la Coupe du monde, on était avec femme et enfants. On allait sortir ?",preparation_condition_physique:"On arrive devant cet internat, le prototype d’un internat d’étudiants et là, on dit stop. On fait une réunion dans le jardin. On refuse d’entrer là-dedans.",heritage_posterite:"Et si on m’avait donné le choix entre un quart de finale de Coupe du monde et une Coupe d’Afrique, j’aurais choisi la CAN. J’aurais tellement aimé en gagner une.",psychologie_emotion:"Jamais je n’ai vu cette équipe sous pression, jamais. Et c’est pour cela, à cause de notre attitude, qui pouvait paraître prétentieuse parfois, que certains disaient qu’on était des branleurs."},joueur:"Khalilou Fadiga",temps_lecture:"10 min"},{slug:"pak-do-ik-1966",index:22,nom:"Pak Do-ik",surnom:null,pays:"Corée du Nord",mondial:"1966",poste:"Attaquant",image:"/cartes_itw/jojo.png",titre_interview:"« À chaque fois, ça me réveille »",lu:!1,archetype:"Amoureux du maillot",archetype_justification:"Il a joué pour la dignité de sa nation, porté par un idéal de représentation collective et de fierté patriotique.",citations:{parcours_professionnel:["Moi, j’étais ouvrier dans une usine d’imprimerie et on devait s’entraîner en parallèle."],contexte_historique:["Les premiers jours, nous étions extrêmement prudents. On restait enfermés dans nos chambres, on avait peur d’aller au contact des gens."],vie_equipe:["Si nous avons pu faire un tel parcours, c’est que notre coach n’était pas stupide. J’étais attaquant et j’avais aussi des devoirs défensifs."],ressentis_emotions:["Je ne peux pas décrire ce que j’ai ressenti, même en cherchant parmi tous les mots qui existent sur cette planète. Même dans nos rêves, on n’avait jamais imaginé battre l’Italie."],grands_moments_sportifs:["Dans mon sommeil, il m’arrive de repenser à cet incroyable scénario qui nous a vus passer de 3-0 à 3-5. À chaque fois, ça me réveille."],technique_jeu:[],ethique_justice:[],anecdotes_vie_privee:["Quand je travaillais, je faisais des matches avec les camarades. Les autres ouvriers racontaient partout que j’étais doué."],preparation_condition_physique:[],heritage_posterite:["Le maire de Middlesbrough nous a remis à chacun un plateau d’argent avec une coupe en verre sur laquelle est gravé “VIIIe Coupe du monde ”. Nous l’avons tous gardé comme une antiquité."],psychologie_emotion:["Au lieu de se morfondre de devoir les affronter, on s’est juste dit : allons-y et essayons de faire un truc."]},date_publication:"03/07/2014",resume:"La Corée du Nord 1966 Cela reste peut-être la plus grande surprise de l’histoire de la Coupe du monde.",citation_forte:"Moi, j’étais ouvrier dans une usine d’imprimerie et on devait s’entraîner en parallèle.",archetypes_ids:["le_curieux"],theme_citations:{parcours_professionnel:"Moi, j’étais ouvrier dans une usine d’imprimerie et on devait s’entraîner en parallèle.",contexte_historique:"Les premiers jours, nous étions extrêmement prudents. On restait enfermés dans nos chambres, on avait peur d’aller au contact des gens.",vie_equipe:"Si nous avons pu faire un tel parcours, c’est que notre coach n’était pas stupide. J’étais attaquant et j’avais aussi des devoirs défensifs.",ressentis_emotions:"Je ne peux pas décrire ce que j’ai ressenti, même en cherchant parmi tous les mots qui existent sur cette planète. Même dans nos rêves, on n’avait jamais imaginé battre l’Italie.",grands_moments_sportifs:"Dans mon sommeil, il m’arrive de repenser à cet incroyable scénario qui nous a vus passer de 3-0 à 3-5. À chaque fois, ça me réveille.",anecdotes_vie_privee:"Quand je travaillais, je faisais des matches avec les camarades. Les autres ouvriers racontaient partout que j’étais doué.",heritage_posterite:"Le maire de Middlesbrough nous a remis à chacun un plateau d’argent avec une coupe en verre sur laquelle est gravé “VIIIe Coupe du monde ”. Nous l’avons tous gardé comme une antiquité.",psychologie_emotion:"Au lieu de se morfondre de devoir les affronter, on s’est juste dit : allons-y et essayons de faire un truc."},joueur:"Pak Do-ik",temps_lecture:"11 min"},{slug:"frank-leboeuf-1998",index:23,nom:"Frank Lebœuf",surnom:null,pays:"France",mondial:"1998",poste:"Défenseur",image:"/cartes_itw/Leboeuf.png",titre_interview:"« On a commencé à dire que j’avais filé du pognon à Bilic »",lu:!1,archetype:"Le supporter",archetype_justification:"Il évoque avec nostalgie l'énergie positive et la communion unique avec le public français en 1998.",citations:{parcours_professionnel:[],contexte_historique:["Tu es en France, tu affrontes le cliché de la plus belle équipe au monde... On est aussi dans le cliché de la France, qui fut le petit Brésil dans les années 1980, et on met une tannée au Brésil..."],vie_equipe:["Aimé Jacquet ne me dit rien pendant trois jours. Il ne me fait pas la gueule, je pense qu’il n’a simplement pas envie de me parler.","Je me suis engueulé avec Marcel (Desailly) et “Dédé” (Deschamps) parce qu’ils avaient affiché la photo où je suis avec Bilic dans la salle à manger de Clairefontaine."],ressentis_emotions:["Je me suis senti comme une grosse merde et, en même temps, je trouvais ça injuste.","Alors au final, le match se passe bien, mais le 12 juillet 1998, c’est le pire jour de ma vie. La plus belle journée de ma vie, mais le pire jour aussi."],grands_moments_sportifs:["On a beaucoup parlé de mon tacle sur Ronaldo. Papapapapapa, le gars va tellement vite que tu ne le vois plus, mais moi, je ne regardais pas les jambes, je ne regardais que le ballon."],technique_jeu:["Je fais croire que je vais le suivre et j’ouvre la porte pour qu’il donne le ballon à Ronaldo. Il lui donne et j’anticipe pour fermer."],ethique_justice:["On a commencé à dire que j’avais filé du pognon à Bilic pour qu’il fasse expulser Lolo."],anecdotes_vie_privee:["J’avais dit à mon ex-femme : “Si on perd la finale, on ne revient plus en France, parce je vais morfler comme jamais.”"],preparation_condition_physique:["Je me souviens être arrivé au Stade de France à 180 pulsations en sortant du bus."],heritage_posterite:["Je pensais qu’on allait tomber dans l’oubli, mais, depuis Knysna, il y a une telle nostalgie que nous sommes devenus des gens vraiment biens."],psychologie_emotion:["J’étais concentré comme jamais dans ma vie. Même quand on avait le ballon, je me disais : “Il est où l’autre enfoiré ?”"]},date_publication:"04/07/2014",resume:"a jeté un bref coup d’œil aux coupures de presse de l’époque, posées devant lui sur la table de bistrot, avant de les rejeter sans regret.",citation_forte:"Tu es en France, tu affrontes le cliché de la plus belle équipe au monde... On est aussi dans le cliché de la France, qui fut le petit Brésil dans les années 1980, et on met une tannée au Brésil...",archetypes_ids:["le_curieux"],theme_citations:{contexte_historique:"Tu es en France, tu affrontes le cliché de la plus belle équipe au monde... On est aussi dans le cliché de la France, qui fut le petit Brésil dans les années 1980, et on met une tannée au Brésil...",vie_equipe:"Aimé Jacquet ne me dit rien pendant trois jours. Il ne me fait pas la gueule, je pense qu’il n’a simplement pas envie de me parler.",ressentis_emotions:"Je me suis senti comme une grosse merde et, en même temps, je trouvais ça injuste.",grands_moments_sportifs:"On a beaucoup parlé de mon tacle sur Ronaldo. Papapapapapa, le gars va tellement vite que tu ne le vois plus, mais moi, je ne regardais pas les jambes, je ne regardais que le ballon.",technique_jeu:"Je fais croire que je vais le suivre et j’ouvre la porte pour qu’il donne le ballon à Ronaldo. Il lui donne et j’anticipe pour fermer.",ethique_justice:"On a commencé à dire que j’avais filé du pognon à Bilic pour qu’il fasse expulser Lolo.",anecdotes_vie_privee:"J’avais dit à mon ex-femme : “Si on perd la finale, on ne revient plus en France, parce je vais morfler comme jamais.”",preparation_condition_physique:"Je me souviens être arrivé au Stade de France à 180 pulsations en sortant du bus.",heritage_posterite:"Je pensais qu’on allait tomber dans l’oubli, mais, depuis Knysna, il y a une telle nostalgie que nous sommes devenus des gens vraiment biens.",psychologie_emotion:"J’étais concentré comme jamais dans ma vie. Même quand on avait le ballon, je me disais : “Il est où l’autre enfoiré ?”"},joueur:"Frank Lebœuf",temps_lecture:"9 min"},{slug:"sergio-goycochea-1990",index:24,nom:"Sergio Goycochea",surnom:null,pays:"Argentine",mondial:"1990",poste:"Gardien",image:"/cartes_itw/Goycochea.png",titre_interview:"« J’étais plus populaire que les Rolling Stones »",lu:!1,archetype:"Le supporter",archetype_justification:"Il vibre pour la ferveur des tribunes et le partage de l'émotion collective, notamment lors de l'hymne national.",citations:{parcours_professionnel:["Je suis parti en Italie dans l’anonymat le plus complet. On m’appelle en sélection comme numéro 2 et je termine titulaire et finaliste d’une Coupe du monde."],contexte_historique:["Vingt-cinq ans après, les gens te racontent cette Coupe du monde comme si elle avait eu lieu l’an passé. Mais il y a une autre raison : cette finale a été la dernière disputée par l’Argentine."],vie_equipe:["Mes coéquipiers m’ont entouré, je me suis agenouillé et j’ai vidé ma vessie et on a gagné. Alors on a répété la même scène contre l’Italie."],ressentis_emotions:["Quand l’arbitre a sifflé penalty, j’ai regardé immédiatement l’horloge du stade. C’était la 84e minute. Je me suis dit que c’était comme le cinquième tir au but d’une série.","Après avoir remplacé Pumpido en cours de match (...) quand on est revenus au vestiaire, je me suis assis dans un coin, à l’écart, et j’ai pleuré."],grands_moments_sportifs:["Quatre au total. Deux contre la Yougoslavie (0-0, 3-2 aux t.a.b.), deux contre l’Italie (1-1, 4-3 aux t.a.b.), et il m’a manqué quelques centimètres pour attraper celui de Brehme, en finale contre l’Allemagne."],technique_jeu:["Ni truc, ni secret mais on sait quel tireur on a en face. S’il est rusé ou “rustique’’.","Je ne peux pas expliquer pourquoi, dans 70 % des penalties, je plongeais du même côté, à ma droite. Question de feeling."],ethique_justice:["J’ai eu la sensation qu’il allait tirer sur ma droite à mi-hauteur. Il a frappé à droite, mais au ras du sol. On ne va pas refaire l’histoire, mais l’arbitre s’est trompé. Il n’y avait pas faute."],anecdotes_vie_privee:["Je me suis marié civilement en décembre 1989. (...) à 15 heures, j’étais sur le terrain avec la sélection.","J’ai fait une conférence de presse et j’ai tout raconté. C’est pour cela que la Coupe du monde 1990, deux ans plus tard, où j’étais numéro 3 au départ, a été la plus belle revanche de ma carrière."],preparation_condition_physique:["Sauf que le Championnat colombien a été suspendu parce qu’un arbitre avait été assassiné. Je n’ai donc pas joué entre décembre 1989 et mai 1990."],heritage_posterite:["À mon retour en Argentine, j’étais plus populaire que les Rolling Stones. J’appelle cela un destin béni."],psychologie_emotion:["J’ai cette particularité : quand tout va bien, je fonce tête baissée et je ne me pose pas de question. Mais attention, au lieu d’être mon point fort, chez moi, c’est un point faible."]},date_publication:"05/07/2014",resume:"« J’étais plus populaire que les Rolling Stones » SERGIO GOYCOCHEA, gardien remplaçant de l’Argentine en 1990, est devenu titulaire dès le deuxième match et, grâce à ses exploits, a accédé au rang de star.",citation_forte:"Je suis parti en Italie dans l’anonymat le plus complet. On m’appelle en sélection comme numéro 2 et je termine titulaire et finaliste d’une Coupe du monde.",archetypes_ids:["le_curieux"],theme_citations:{parcours_professionnel:"Je suis parti en Italie dans l’anonymat le plus complet. On m’appelle en sélection comme numéro 2 et je termine titulaire et finaliste d’une Coupe du monde.",contexte_historique:"Vingt-cinq ans après, les gens te racontent cette Coupe du monde comme si elle avait eu lieu l’an passé. Mais il y a une autre raison : cette finale a été la dernière disputée par l’Argentine.",vie_equipe:"Mes coéquipiers m’ont entouré, je me suis agenouillé et j’ai vidé ma vessie et on a gagné. Alors on a répété la même scène contre l’Italie.",ressentis_emotions:"Quand l’arbitre a sifflé penalty, j’ai regardé immédiatement l’horloge du stade. C’était la 84e minute. Je me suis dit que c’était comme le cinquième tir au but d’une série.",grands_moments_sportifs:"Quatre au total. Deux contre la Yougoslavie (0-0, 3-2 aux t.a.b.), deux contre l’Italie (1-1, 4-3 aux t.a.b.), et il m’a manqué quelques centimètres pour attraper celui de Brehme, en finale contre l’Allemagne.",technique_jeu:"Ni truc, ni secret mais on sait quel tireur on a en face. S’il est rusé ou “rustique’’.",ethique_justice:"J’ai eu la sensation qu’il allait tirer sur ma droite à mi-hauteur. Il a frappé à droite, mais au ras du sol. On ne va pas refaire l’histoire, mais l’arbitre s’est trompé. Il n’y avait pas faute.",anecdotes_vie_privee:"Je me suis marié civilement en décembre 1989. (...) à 15 heures, j’étais sur le terrain avec la sélection.",preparation_condition_physique:"Sauf que le Championnat colombien a été suspendu parce qu’un arbitre avait été assassiné. Je n’ai donc pas joué entre décembre 1989 et mai 1990.",heritage_posterite:"À mon retour en Argentine, j’étais plus populaire que les Rolling Stones. J’appelle cela un destin béni.",psychologie_emotion:"J’ai cette particularité : quand tout va bien, je fonce tête baissée et je ne me pose pas de question. Mais attention, au lieu d’être mon point fort, chez moi, c’est un point faible."},joueur:"Sergio Goycochea",temps_lecture:"10 min"},{slug:"amarildo-1962",index:25,nom:"Amarildo",surnom:"Le remplaçant de l'irremplaçable",pays:"Brésil",mondial:"1962",poste:"Attaquant",image:"/cartes_itw/Amarildo.png",titre_interview:"« Quand Pelé s’est blessé, tout le monde pleurait »",lu:!1,archetype:"L'artiste",archetype_justification:"Teigneux et fier, il a su transformer son opportunité en une démonstration de talent pur pour remplacer le « Roi ».",citations:{parcours_professionnel:["Après la Coupe du monde 1966, la Fédération brésilienne a décidé de ne plus convoquer des joueurs évoluant dans des Championnats étrangers. Beaucoup de joueurs, comme moi, n’ont plus été appelés."],contexte_historique:["À l’époque, il n’y avait qu’une seule autre star comparable à Pelé aux yeux des Brésiliens, c’était Garrincha."],vie_equipe:["Pelé était notre premier supporter. Il m’a dit : ‘’Je sais ce qui se dit sur toi et sur le Brésil, maintenant que je suis indisponible, mais je sais aussi de quoi tu es capable.’’"],ressentis_emotions:["Jouer, pas jouer, j’étais prêt à tout, moi qui n’avais pas joué en sélections de jeunes. Mais je n’attendais pas fébrilement les bulletins de santé de Pelé.","J’ai marqué les deux buts de la victoire et réussi l’un des meilleurs matches de ma vie. Un grand moment."],grands_moments_sportifs:["Sur le premier c’est Zagallo qui mène l’attaque, et lui, je le connais par cœur. Cette action, on l’a répétée des dizaines de fois à Botafogo.","C’est seulement quand j’ai eu le trophée Jules Rimet dans les mains que je me suis dit : si je n’avais pas marqué contre l’Espagne, que se serait-il passé, qui serais-je aujourd’hui ?"],technique_jeu:["Tactiquement, j’avais la chance d’avoir les qualités pour m’adapter à tout ou presque. Je pouvais jouer pratiquement partout sur le terrain."],ethique_justice:["D’un point de vue sportif, j’étais indiscipliné et je le revendiquais. Je savais ce que je voulais, on ne me faisait pas dévier comme ça."],anecdotes_vie_privee:[],preparation_condition_physique:[],heritage_posterite:["Dans toute ma carrière, de 1958 à 1974, je n’ai jamais souhaité de mal à quelqu’un, mais cette blessure de Pelé a été décisive dans ma carrière."],psychologie_emotion:["J’avais un tempérament particulier. Un caractère de gagneur. Quoi que je fasse, je voulais gagner.","Je voulais démontrer que ce n’était pas parce qu’il avait perdu un très grand joueur que le Brésil avait perdu toute chance de gagner le Mondial !"]},date_publication:"06/07/2014",resume:"« Quand Pelé s’est blessé, tout le monde pleurait » AMARILDO n’aurait jamais dû jouer lors de la Coupe du monde 1962.",citation_forte:"Après la Coupe du monde 1966, la Fédération brésilienne a décidé de ne plus convoquer des joueurs évoluant dans des Championnats étrangers. Beaucoup de joueurs, comme moi, n’ont plus été appelés.",archetypes_ids:["l_historien","le_patriote","le_supporter"],theme_citations:{parcours_professionnel:"Après la Coupe du monde 1966, la Fédération brésilienne a décidé de ne plus convoquer des joueurs évoluant dans des Championnats étrangers. Beaucoup de joueurs, comme moi, n’ont plus été appelés.",contexte_historique:"À l’époque, il n’y avait qu’une seule autre star comparable à Pelé aux yeux des Brésiliens, c’était Garrincha.",vie_equipe:"Pelé était notre premier supporter. Il m’a dit : ‘’Je sais ce qui se dit sur toi et sur le Brésil, maintenant que je suis indisponible, mais je sais aussi de quoi tu es capable.’’",ressentis_emotions:"Jouer, pas jouer, j’étais prêt à tout, moi qui n’avais pas joué en sélections de jeunes. Mais je n’attendais pas fébrilement les bulletins de santé de Pelé.",grands_moments_sportifs:"Sur le premier c’est Zagallo qui mène l’attaque, et lui, je le connais par cœur. Cette action, on l’a répétée des dizaines de fois à Botafogo.",technique_jeu:"Tactiquement, j’avais la chance d’avoir les qualités pour m’adapter à tout ou presque. Je pouvais jouer pratiquement partout sur le terrain.",ethique_justice:"D’un point de vue sportif, j’étais indiscipliné et je le revendiquais. Je savais ce que je voulais, on ne me faisait pas dévier comme ça.",heritage_posterite:"Dans toute ma carrière, de 1958 à 1974, je n’ai jamais souhaité de mal à quelqu’un, mais cette blessure de Pelé a été décisive dans ma carrière.",psychologie_emotion:"J’avais un tempérament particulier. Un caractère de gagneur. Quoi que je fasse, je voulais gagner."},joueur:"Amarildo",temps_lecture:"8 min"},{slug:"bora-milutinovic-selectionneur",index:26,nom:"Velibor Milutinovic",surnom:"Bora",pays:"Serbie",mondial:"1986, 1990, 1994, 1998, 2002",poste:"Sélectionneur",image:"/cartes_itw/Milutinovic.png",titre_interview:"« J’ai gagné cinq Coupes du monde… »",lu:!1,archetype:"Le globe-trotter magicien",archetype_justification:"Entraîneur atypique et citoyen du monde, il a dirigé cinq sélections différentes en Coupe du monde, réussissant souvent l'exploit de passer le premier tour avec des équipes inattendues.",citations:{parcours_professionnel:["C’était la première fois qu’un étranger occupait ce poste [au Mexique en 1983].","J’ai participé au rendez-vous planétaire avec cinq sélections différentes."],contexte_historique:["Pour le poste aux États-Unis, il y avait trois candidats : Beckenbauer, Cruyff et moi."],vie_equipe:["J’ai mis dehors les cinq joueurs les plus importants du pays [au Costa Rica]. Ils n’étaient pas faits pour disputer des matches de Coupe du monde !"],ressentis_emotions:["Cent vingt mille personnes qui chantaient l’hymne national sans la musique. C’est mon souvenir le plus précieux. Quand j’en parle, j’en ai encore la chair de poule."],grands_moments_sportifs:["On fait nul contre la Suisse (1-1) et on bat la Colombie (2-1) avec le sentiment que l’équipe progresse rapidement."],technique_jeu:["J’ai expliqué aux joueurs ce que je voulais avec des gestes. En fait, je leur montrais, balle au pied, ce que je désirais."],ethique_justice:[],anecdotes_vie_privee:["Avec un membre de la Fédération et ma caméra je suis parti filmer, en douce, dans tout le pays, dans les villages les plus reculés, les parents des joueurs.","Je suis allé dans le village en question et j’ai trouvé la vieille personne, la grand-mère [supposée décédée]. Et croyez-moi, elle bougeait bien."],preparation_condition_physique:["Il a fallu beaucoup s’entraîner. Trois séances par jour. À 7 heures, à 11 heures et à 17 heures."],heritage_posterite:["Je suis fier, mais bon… [d'avoir l'Aguila Azteca]","Plus tard, les Chinois m’ont même donné une décoration. La même que celle reçue par ‘’Mon Général’’ (De Gaulle)."],psychologie_emotion:["Un passionné qui a eu la chance que Dieu lui donne l’intuition de voir ce que les autres ne voient pas."]},date_publication:"07/07/2014",resume:"Bora Milutinovic UN « OURAGAN » GLOBE-TROTTER « BORA ». Voilà un diminutif (son vrai prénom est Velibor) qui n’a pas été choisi par hasard.",citation_forte:"C’était la première fois qu’un étranger occupait ce poste [au Mexique en 1983].",archetypes_ids:["le_curieux"],theme_citations:{parcours_professionnel:"C’était la première fois qu’un étranger occupait ce poste [au Mexique en 1983].",contexte_historique:"Pour le poste aux États-Unis, il y avait trois candidats : Beckenbauer, Cruyff et moi.",vie_equipe:"J’ai mis dehors les cinq joueurs les plus importants du pays [au Costa Rica]. Ils n’étaient pas faits pour disputer des matches de Coupe du monde !",ressentis_emotions:"Cent vingt mille personnes qui chantaient l’hymne national sans la musique. C’est mon souvenir le plus précieux. Quand j’en parle, j’en ai encore la chair de poule.",grands_moments_sportifs:"On fait nul contre la Suisse (1-1) et on bat la Colombie (2-1) avec le sentiment que l’équipe progresse rapidement.",technique_jeu:"J’ai expliqué aux joueurs ce que je voulais avec des gestes. En fait, je leur montrais, balle au pied, ce que je désirais.",anecdotes_vie_privee:"Avec un membre de la Fédération et ma caméra je suis parti filmer, en douce, dans tout le pays, dans les villages les plus reculés, les parents des joueurs.",preparation_condition_physique:"Il a fallu beaucoup s’entraîner. Trois séances par jour. À 7 heures, à 11 heures et à 17 heures.",heritage_posterite:"Je suis fier, mais bon… [d'avoir l'Aguila Azteca]",psychologie_emotion:"Un passionné qui a eu la chance que Dieu lui donne l’intuition de voir ce que les autres ne voient pas."},joueur:"Velibor Milutinovic"},{slug:"byron-moreno-2002",index:27,nom:"Byron Moreno",surnom:"El Justiciero",pays:"Équateur",mondial:"2002",poste:"Arbitre",image:"/cartes_itw/Moreno.png",titre_interview:"« Le seul argent que j’ai reçu a été celui de la FIFA »",lu:!1,archetype:"Le curieux",archetype_justification:"Sa trajectoire de vie, entre arbitrages polémiques et déboires personnels à New York, est riche en anecdotes hors-normes.",citations:{parcours_professionnel:["Ça remonte à mes débuts dans le football professionnel, en 1993. En Équateur, dans le Championnat de Première Division, je sortais en moyenne 2,5 cartons rouges par match.","Le 23 mars 2003, j’ai convoqué la presse. [...] et je leur ai annoncé mon retrait officiel de l’arbitrage."],contexte_historique:["Les Italiens dénoncèrent un complot de la part de la FIFA, accusée d’être de mèche avec le pays organisateur."],vie_equipe:[],ressentis_emotions:["Dans l’avion, à plusieurs reprises, je me suis levé pour aller aux toilettes. Je voulais tout vider dans la cuvette. Il m’a juste manqué du courage."],grands_moments_sportifs:["Totti a simulé un contact avec un joueur sud-coréen et s’est laissé tomber. Sur les deux hors-jeu (un seul en fait), je n’ai fait que suivre la décision de mon juge de ligne."],technique_jeu:[],ethique_justice:["Je suis convaincu qu’il [Trapattoni] a orchestré la campagne de dénigrement pour fuir ses responsabilités. Si quelqu’un a conspiré, c’est Trapattoni","Non, rien, je le jure. Le seul argent que j’ai reçu a été celui de la FIFA."],anecdotes_vie_privee:["C’est la plus grande erreur de ma vie. Une vraie folie. J’étais au fond du trou, économiquement, quand j’ai dû faire face à un cas de force majeure.","Au total, j’ai fait deux ans, deux mois et douze jours de détention."],preparation_condition_physique:[],heritage_posterite:["Un jour, j’ai appris qu’une bande de la mafia italienne de New York avait été arrêtée. J’ai eu leur chef dans ma cellule. On a reparlé bien sûr d’Italie-Corée du Sud."],psychologie_emotion:["J’ai beaucoup appris de ma propre déchéance. J’ai d’abord fait une terrible dépression."]},date_publication:"08/07/2014",resume:"C’est un jeune arbitre de trente-deux ans, Byron Aldemar Moreno Ruales, qui est désigné pour ce huitième de finale de la Coupe du monde 2002 entre la Corée du Sud et l’Italie. Les Asiatiques évoluent à domicile, à Daejeon.",citation_forte:"Ça remonte à mes débuts dans le football professionnel, en 1993. En Équateur, dans le Championnat de Première Division, je sortais en moyenne 2,5 cartons rouges par match.",archetypes_ids:["le_patriote","le_curieux","le_supporter"],theme_citations:{parcours_professionnel:"Ça remonte à mes débuts dans le football professionnel, en 1993. En Équateur, dans le Championnat de Première Division, je sortais en moyenne 2,5 cartons rouges par match.",contexte_historique:"Les Italiens dénoncèrent un complot de la part de la FIFA, accusée d’être de mèche avec le pays organisateur.",ressentis_emotions:"Dans l’avion, à plusieurs reprises, je me suis levé pour aller aux toilettes. Je voulais tout vider dans la cuvette. Il m’a juste manqué du courage.",grands_moments_sportifs:"Totti a simulé un contact avec un joueur sud-coréen et s’est laissé tomber. Sur les deux hors-jeu (un seul en fait), je n’ai fait que suivre la décision de mon juge de ligne.",ethique_justice:"Je suis convaincu qu’il [Trapattoni] a orchestré la campagne de dénigrement pour fuir ses responsabilités. Si quelqu’un a conspiré, c’est Trapattoni",anecdotes_vie_privee:"C’est la plus grande erreur de ma vie. Une vraie folie. J’étais au fond du trou, économiquement, quand j’ai dû faire face à un cas de force majeure.",heritage_posterite:"Un jour, j’ai appris qu’une bande de la mafia italienne de New York avait été arrêtée. J’ai eu leur chef dans ma cellule. On a reparlé bien sûr d’Italie-Corée du Sud.",psychologie_emotion:"J’ai beaucoup appris de ma propre déchéance. J’ai d’abord fait une terrible dépression."},joueur:"Byron Moreno",temps_lecture:"9 min"},{slug:"saeed-ali-al-owairan-1994",index:28,nom:"Saeed Ali Al-Owairan",surnom:null,pays:"Arabie saoudite",mondial:"1994",poste:"Milieu offensif",image:"/cartes_itw/Al-oweiran.png",titre_interview:"« J’ai quand même eu un destin assez exceptionnel »",lu:!1,archetype:"L'artiste",archetype_justification:"Auteur d'un but qualifié de « magique », il reste le symbole de la beauté d'un geste individuel inattendu.",citations:{parcours_professionnel:["J’ai reçu beaucoup d’offres de clubs européens. [...] Mais, à l’époque, la Fédération saoudienne ne nous autorisait pas à nous expatrier."],contexte_historique:["En cherchant bien, je crois que ce match coïncidait avec les épreuves du baccalauréat en Arabie saoudite. Au pays, les gens ont dû regarder cette rencontre à 2 heures du matin."],vie_equipe:["Juste après le coup de sifflet final quand, dans le vestiaire, un de mes partenaires est venu me dire : « Qu’est-ce que tu nous as fait Saeed ? »"],ressentis_emotions:["C’était encore beaucoup plus fort que ça [un orgasme]. Même si je le reconnais, la comparaison est très bonne."],grands_moments_sportifs:["Je remonte tout le terrain, j’élimine quelques joueurs belges (cinq) et je frappe du droit. Presque naturellement."],technique_jeu:["Moi, d’habitude, je jouais derrière les attaquants, mais là, sur une action de jeu, je me suis retrouvé dans mon propre camp."],ethique_justice:["Des journaux américains, je ne vais pas citer leurs noms, m’ont promis un million de dollars pour raconter mon histoire. Des contrats ont été signés [...] je n’ai jamais vu cet argent."],anecdotes_vie_privee:["J’ai été invité dans une soirée à Riyad, oui, où il y avait beaucoup de personnes, dont des femmes (des prostituées libanaises).","La police religieuse (les Muttawa) est venue me chercher chez moi. [...] J’ai pris sept mois."],preparation_condition_physique:["Je pouvais recevoir mes amis, les joueurs de mon club qui sont tous venus me voir. Je pouvais aussi m’entraîner tous les matins."],heritage_posterite:["À l’époque, la FIFA l’avait, en fait, classé à la sixième place, si je ne me trompe pas. Mais, depuis peu, il a été reclassé à la troisième place."],psychologie_emotion:["J’étais un battant sur le terrain, il a fallu que je le devienne en dehors pour supporter tout ça."]},date_publication:"09/07/2014",resume:"Le 29 juin 1994, la vie de Saeed Ali al-Owairan a soudainement basculé dans l’irrationnel.",citation_forte:"J’ai reçu beaucoup d’offres de clubs européens. [...] Mais, à l’époque, la Fédération saoudienne ne nous autorisait pas à nous expatrier.",archetypes_ids:["le_curieux"],theme_citations:{parcours_professionnel:"J’ai reçu beaucoup d’offres de clubs européens. [...] Mais, à l’époque, la Fédération saoudienne ne nous autorisait pas à nous expatrier.",contexte_historique:"En cherchant bien, je crois que ce match coïncidait avec les épreuves du baccalauréat en Arabie saoudite. Au pays, les gens ont dû regarder cette rencontre à 2 heures du matin.",vie_equipe:"Juste après le coup de sifflet final quand, dans le vestiaire, un de mes partenaires est venu me dire : « Qu’est-ce que tu nous as fait Saeed ? »",ressentis_emotions:"C’était encore beaucoup plus fort que ça [un orgasme]. Même si je le reconnais, la comparaison est très bonne.",grands_moments_sportifs:"Je remonte tout le terrain, j’élimine quelques joueurs belges (cinq) et je frappe du droit. Presque naturellement.",technique_jeu:"Moi, d’habitude, je jouais derrière les attaquants, mais là, sur une action de jeu, je me suis retrouvé dans mon propre camp.",ethique_justice:"Des journaux américains, je ne vais pas citer leurs noms, m’ont promis un million de dollars pour raconter mon histoire. Des contrats ont été signés [...] je n’ai jamais vu cet argent.",anecdotes_vie_privee:"J’ai été invité dans une soirée à Riyad, oui, où il y avait beaucoup de personnes, dont des femmes (des prostituées libanaises).",preparation_condition_physique:"Je pouvais recevoir mes amis, les joueurs de mon club qui sont tous venus me voir. Je pouvais aussi m’entraîner tous les matins.",heritage_posterite:"À l’époque, la FIFA l’avait, en fait, classé à la sixième place, si je ne me trompe pas. Mais, depuis peu, il a été reclassé à la troisième place.",psychologie_emotion:"J’étais un battant sur le terrain, il a fallu que je le devienne en dehors pour supporter tout ça."},joueur:"Saeed Ali Al-Owairan",temps_lecture:"9 min"},{slug:"stephane-guivarch-1998",index:29,nom:"Stéphane Guivarc'h",surnom:null,pays:"France",mondial:"1998",poste:"Attaquant",image:"/cartes_itw/Guivarc'h.png",titre_interview:"« J’aurais préféré en marquer vingt de moins en club et mettre ces deux-là ! »",lu:!1,archetype:"Le supporter",archetype_justification:"Il trouve son équilibre dans la passion locale de sa région et le souvenir du bonheur simple partagé avec les gens.",citations:{parcours_professionnel:["Je suis parti de la Ligue 2, je suis retombé en National avec Guingamp, après on a fait deux montées successives. Ensuite j’arrive à Auxerre [...] je finis meilleur buteur à Rennes et à Auxerre."],contexte_historique:["Avant la compétition, on se faisait tailler comme ce n’est pas permis ! Comme quoi, un groupe et une équipe sont capables de soulever des montagnes."],vie_equipe:["Chacun avait son caractère. Certes, je suis arrivé à vingt-sept ans, mais quand on débarque en équipe de France, on n’ouvre pas sa bouche tout de suite."],ressentis_emotions:["Ce qui est dur, c’est de ne pas avoir eu la récompense de ce petit but.","Aujourd’hui, je le prends avec humour, mais sur le coup ça m’a mis les glandes [vol du sac après la finale]."],grands_moments_sportifs:["Je revois encore cette occase où je frappe pied gauche et Taffarel se couche bien. Et puis cette autre situation en seconde période..."],technique_jeu:["J’étais seul à la pointe de l’attaque. Il n’y avait pas d’hommes de couloir, comme je pouvais en avoir à Auxerre, qui centrent constamment et qui attirent du monde à eux."],ethique_justice:["Le président Jacques Chirac et Lionel Jospin [...] nous avaient dit à l’époque : “Vous avez fait quelque chose d’extraordinaire pour la France : vous ne serez taxés qu’à 15 % !” [...] Trois ans plus tard : boum, redressé !"],anecdotes_vie_privee:["De toute façon, j’avais toujours dit qu’après ma carrière, je serais revenu dans le secteur (Concarneau et le Finistère)."],preparation_condition_physique:["J’ai fini la compétition avec des douleurs, c’est donc que je n’étais pas à 100 %.","Je me souviens qu’à Tignes, en stage de préparation, on avait fait une marche en raquette et je m’étais fait un point de contracture. La fatigue était déjà très présente."],heritage_posterite:["Seize ans plus tard, nous ne sommes encore que 22 champions du monde. On a marqué l’histoire."],psychologie_emotion:["Le devoir avait été accompli, mais pour un attaquant comme moi, il manquait ce but. Ça m’a titillé l’esprit."]},date_publication:"10/07/2014",resume:"Arrivé sur le tard en équipe de France – à vingt-sept ans et quelques mois avant la Coupe du monde 1998 –, Stéphane Guivarc’h vit avec ce paradoxe :",citation_forte:"Je suis parti de la Ligue 2, je suis retombé en National avec Guingamp, après on a fait deux montées successives. Ensuite j’arrive à Auxerre [...] je finis meilleur buteur à Rennes et à Auxerre.",archetypes_ids:["le_patriote","le_supporter","le_curieux"],theme_citations:{parcours_professionnel:"Je suis parti de la Ligue 2, je suis retombé en National avec Guingamp, après on a fait deux montées successives. Ensuite j’arrive à Auxerre [...] je finis meilleur buteur à Rennes et à Auxerre.",contexte_historique:"Avant la compétition, on se faisait tailler comme ce n’est pas permis ! Comme quoi, un groupe et une équipe sont capables de soulever des montagnes.",vie_equipe:"Chacun avait son caractère. Certes, je suis arrivé à vingt-sept ans, mais quand on débarque en équipe de France, on n’ouvre pas sa bouche tout de suite.",ressentis_emotions:"Ce qui est dur, c’est de ne pas avoir eu la récompense de ce petit but.",grands_moments_sportifs:"Je revois encore cette occase où je frappe pied gauche et Taffarel se couche bien. Et puis cette autre situation en seconde période...",technique_jeu:"J’étais seul à la pointe de l’attaque. Il n’y avait pas d’hommes de couloir, comme je pouvais en avoir à Auxerre, qui centrent constamment et qui attirent du monde à eux.",ethique_justice:"Le président Jacques Chirac et Lionel Jospin [...] nous avaient dit à l’époque : “Vous avez fait quelque chose d’extraordinaire pour la France : vous ne serez taxés qu’à 15 % !” [...] Trois ans plus tard : boum, redressé !",anecdotes_vie_privee:"De toute façon, j’avais toujours dit qu’après ma carrière, je serais revenu dans le secteur (Concarneau et le Finistère).",preparation_condition_physique:"J’ai fini la compétition avec des douleurs, c’est donc que je n’étais pas à 100 %.",heritage_posterite:"Seize ans plus tard, nous ne sommes encore que 22 champions du monde. On a marqué l’histoire.",psychologie_emotion:"Le devoir avait été accompli, mais pour un attaquant comme moi, il manquait ce but. Ça m’a titillé l’esprit."},joueur:"Stéphane Guivarc'h",temps_lecture:"9 min"},{slug:"luis-ricardo-mora-1982",index:30,nom:"Luis Ricardo Mora",surnom:null,pays:"Salvador",mondial:"1982",poste:"Gardien",image:"/cartes_itw/Mora.png",titre_interview:"« On a tenté de m’assassiner »",lu:!1,archetype:"Le bouc émissaire survivant",archetype_justification:"Gardien ayant encaissé le record de dix buts en un match (10-1 contre la Hongrie), il est devenu le bouc émissaire d'une nation en guerre civile et a même survécu à une tentative d'assassinat à son retour au pays.",citations:{parcours_professionnel:["Deux mois plus tard, je repartais en Espagne pour jouer à Murcie (1982-1983).","Pendant mon exil au Guatemala, j’ai rencontré ma femme, on a eu trois enfants et, comme gardien de but d’Aurora (1989-1993), je suis devenu l’homme le plus populaire du football guatémaltèque.","Je suis, aujourd’hui, directeur des sports de la ville de San Salvador."],contexte_historique:["Parce qu’il ne faut pas l’oublier, notre pays traversait une guerre civile.","J’ai vu des gamins de quatorze ans faire défiler des prisonniers dans la rue et décider de qui allait vivre ou mourir.","Dans un tout petit pays [...], sans électricité, sans réseau routier et sans ressources naturelles jusqu’au milieu des années 1990, ce conflit armé a eu des conséquences bien plus dramatiques sur la politique sportive du Salvador que notre échec espagnol."],vie_equipe:["Pas un de mes coéquipiers ne m’a laissé tomber. Chaque fois qu’ils en ont eu l’occasion, ils m’ont entouré, appuyé, soutenu.","C’était une génération exceptionnelle, un état d’esprit, une solidarité irréprochables au milieu de la guerre."],ressentis_emotions:["Je suis marqué à vie par cet épisode et si je disais le contraire, je mentirais.","J’étais comme un lépreux au temps des Romains. On est venu jeter des pierres sur ma maison."],grands_moments_sportifs:["Pour moi, la défaite contre la Hongrie est un accident, dû à la méconnaissance totale de l’adversaire.","Si j’avais été désastreux ce 15 juin 1982, comme on a essayé de le faire croire, je pourrais culpabiliser mais j’étais loin d’être catastrophique. J’ai bloqué au moins une dizaine d’occasions très nettes..."],technique_jeu:["Au coup d’envoi, on s’est lancés à l’assaut du but adverse sans savoir qu’en face on avait les champions du monde de la contre-attaque."],ethique_justice:["La Fédération, dès le départ, s’était comportée de façon indigne avec nous, qu’on n’avait pas eu les moyens de se préparer.","Pour se faire élire, il avait arrangé, avec ceux du Costa Rica, une défaite de sa propre sélection."],anecdotes_vie_privee:["Un soir, en allant rendre visite à ma fiancée de l’époque, une voiture m’a suivi et, sans me laisser le temps de descendre, ses occupants ont ouvert le feu sur moi.","On a relevé vingt-deux impacts de balle sur la carrosserie de ma voiture. Aucun ne m’a atteint."],preparation_condition_physique:["C’est par l’intermédiaire d’un proche de la sélection, qui se rendait souvent au Panama, qu’on a acheté nous-mêmes un maillot unique, un short, des chaussettes et des crampons. On était trop fauchés pour s’offrir une tenue d’entraînement et chacun a fait avec celle de son club."],heritage_posterite:["La Fédération a estimé, à tort, que la génération du Mondial 1982 était une pomme pourrie. Tout le groupe, sauf un joueur, Jorge “Magico“ Gonzalez, notre Maradona à nous, a été rayé des cadres.","Mon fils aîné a subi de nombreuses moqueries. Il est devenu un ennemi du football."],psychologie_emotion:["Je suis une tête dure qui met rarement un genou à terre. Mon seul objectif a été d’affronter les événements en face, de démontrer qu’on devait me faire confiance."]},date_publication:"11/07/2014",resume:"EN 1982, le Salvador dispute sa deuxième Coupe du monde après celle de 1970 au Mexique, où il n’a gagné aucun de ses trois matches ni marqué le moindre but.",citation_forte:"Deux mois plus tard, je repartais en Espagne pour jouer à Murcie (1982-1983).",archetypes_ids:["le_patriote","le_stratege","l_historien"],theme_citations:{parcours_professionnel:"Deux mois plus tard, je repartais en Espagne pour jouer à Murcie (1982-1983).",contexte_historique:"Parce qu’il ne faut pas l’oublier, notre pays traversait une guerre civile.",vie_equipe:"Pas un de mes coéquipiers ne m’a laissé tomber. Chaque fois qu’ils en ont eu l’occasion, ils m’ont entouré, appuyé, soutenu.",ressentis_emotions:"Je suis marqué à vie par cet épisode et si je disais le contraire, je mentirais.",grands_moments_sportifs:"Pour moi, la défaite contre la Hongrie est un accident, dû à la méconnaissance totale de l’adversaire.",technique_jeu:"Au coup d’envoi, on s’est lancés à l’assaut du but adverse sans savoir qu’en face on avait les champions du monde de la contre-attaque.",ethique_justice:"La Fédération, dès le départ, s’était comportée de façon indigne avec nous, qu’on n’avait pas eu les moyens de se préparer.",anecdotes_vie_privee:"Un soir, en allant rendre visite à ma fiancée de l’époque, une voiture m’a suivi et, sans me laisser le temps de descendre, ses occupants ont ouvert le feu sur moi.",preparation_condition_physique:"C’est par l’intermédiaire d’un proche de la sélection, qui se rendait souvent au Panama, qu’on a acheté nous-mêmes un maillot unique, un short, des chaussettes et des crampons. On était trop fauchés pour s’offrir une tenue d’entraînement et chacun a fait avec celle de son club.",heritage_posterite:"La Fédération a estimé, à tort, que la génération du Mondial 1982 était une pomme pourrie. Tout le groupe, sauf un joueur, Jorge “Magico“ Gonzalez, notre Maradona à nous, a été rayé des cadres.",psychologie_emotion:"Je suis une tête dure qui met rarement un genou à terre. Mon seul objectif a été d’affronter les événements en face, de démontrer qu’on devait me faire confiance."},joueur:"Luis Ricardo Mora"},{slug:"zico-1986",index:31,nom:"Zico",surnom:"Galinho de Quintino",pays:"Brésil",mondial:"1986",poste:"Meneur de jeu",image:"/cartes_itw/Zico_carte_interview.png",titre_interview:"« Ce penalty manqué ne m’a jamais empêché de dormir »",lu:!1,archetype:"L'artiste",archetype_justification:"Pour lui, le football était un art où le numéro 10 devait porter la magie et la création du jeu.",citations:{parcours_professionnel:["Oui, Flamengo a été plus important. Sans aucun doute. Mais on ne peut pas tout à fait comparer.","Avec la Seleçao, les choses n’ont pas bien marché. Du moins, pas comme je l’espérais."],contexte_historique:["Les années 1990 avaient marqué une période un peu sombre. L’idée était de gagner à tout prix. C’était le règne du jeu défensif, de la déconstruction du jeu adverse."],vie_equipe:["C’était une décision de l’entraîneur, Tele Santana. Dans son esprit, il était plus intéressant de me faire entrer en cours de match, quand l’adversaire commencerait à ressentir de la fatigue."],ressentis_emotions:["En fait, les Coupes du monde ne m’auront jamais rendu heureux."],grands_moments_sportifs:["Pour moi, ce penalty ne représente rien. Ce n’est pas un boulet que je traîne. Un penalty est un fait de jeu, rien de plus.","Moi, en tout cas, ce penalty manqué ne m’a jamais empêché de dormir. Je ne l’ai jamais vécu comme la fin du monde."],technique_jeu:["Le 10, c’est le joueur qui pense, articule le jeu, délivre les plus belles passes. Et qui marque aussi des buts. C’est la position où il se crée toujours quelque chose."],ethique_justice:["Il se passe qu’on ne supporte pas de ne pas gagner une Coupe du monde. Alors, il faut toujours des coupables."],anecdotes_vie_privee:[],preparation_condition_physique:["En 1986, c’était spécial. Cette Coupe du monde, je ne voulais pas la jouer…","Je souffrais d’un genou. Je n’avais qu’une envie, c’était de quitter le Mexique et de partir aux États-Unis me faire opérer."],heritage_posterite:["La FIFA me classe, paraît-il, parmi les dix meilleurs joueurs de tous les temps. C’est une très grande satisfaction…","C’est un journal français qui m’a appelé ainsi. Je n’ai jamais su pourquoi. C’est un honneur, parce que Pelé reste le meilleur joueur de l’histoire."],psychologie_emotion:["Il y avait de la pression, oui, mais la majorité des joueurs sont conditionnés pour y faire face.","Un bon joueur n’aura jamais peur de frapper dans un ballon."]},date_publication:"12/07/2014",resume:"« Ce penalty manqué ne m’a jamais empêché de dormir » ZICO considère toujours, vingt-huit ans après le mythique France-Brésil de Guadalajara, que son face-à-face raté avec Joël Bats n’a été qu’une péripétie du match.",citation_forte:"Oui, Flamengo a été plus important. Sans aucun doute. Mais on ne peut pas tout à fait comparer.",archetypes_ids:["l_artiste","le_stratege"],theme_citations:{parcours_professionnel:"Oui, Flamengo a été plus important. Sans aucun doute. Mais on ne peut pas tout à fait comparer.",contexte_historique:"Les années 1990 avaient marqué une période un peu sombre. L’idée était de gagner à tout prix. C’était le règne du jeu défensif, de la déconstruction du jeu adverse.",vie_equipe:"C’était une décision de l’entraîneur, Tele Santana. Dans son esprit, il était plus intéressant de me faire entrer en cours de match, quand l’adversaire commencerait à ressentir de la fatigue.",ressentis_emotions:"En fait, les Coupes du monde ne m’auront jamais rendu heureux.",grands_moments_sportifs:"Pour moi, ce penalty ne représente rien. Ce n’est pas un boulet que je traîne. Un penalty est un fait de jeu, rien de plus.",technique_jeu:"Le 10, c’est le joueur qui pense, articule le jeu, délivre les plus belles passes. Et qui marque aussi des buts. C’est la position où il se crée toujours quelque chose.",ethique_justice:"Il se passe qu’on ne supporte pas de ne pas gagner une Coupe du monde. Alors, il faut toujours des coupables.",preparation_condition_physique:"En 1986, c’était spécial. Cette Coupe du monde, je ne voulais pas la jouer…",heritage_posterite:"La FIFA me classe, paraît-il, parmi les dix meilleurs joueurs de tous les temps. C’est une très grande satisfaction…",psychologie_emotion:"Il y avait de la pression, oui, mais la majorité des joueurs sont conditionnés pour y faire face."},joueur:"Zico",temps_lecture:"9 min"},{slug:"zinedine-zidane-1998-2006",index:32,nom:"Zinédine Zidane",surnom:"Zizou",pays:"France",mondial:"1998, 2002, 2006",poste:"Meneur de jeu",image:"/cartes_itw/Zidane.png",titre_interview:"« Je n’imaginais pas tout ce qui allait se passer après »",lu:!1,archetype:"L'artiste",archetype_justification:"Il a marqué le Mondial par une esthétique du jeu exceptionnelle et des gestes capables de transformer un match en spectacle.",citations:{parcours_professionnel:["J’ai gagné ce trophée, j’ai soulevé cette coupe : c’est pour ça que l’on joue au foot, finalement. Pour gagner des trophées."],contexte_historique:[],vie_equipe:["J’ai toujours fait et je ferai toujours tout pour l’équipe. Ce n’est jamais pour moi, perso. Je n’ai jamais été égoïste et je ne le serai jamais."],ressentis_emotions:["Je savais bien que j’avais fait quelque chose de top, que gagner une finale de Coupe du monde et marquer deux fois, ça n’arrive pas tous les jours. La force qui t’envahit sur le moment, l’intensité émotionnelle… Je n’ai jamais revécu cela.","C’est une “cata” de voir ça du banc, je vous le confirme. C’est une catastrophe."],grands_moments_sportifs:["L’image est là. Je vois exactement ce que je fais. Je le revis avec l’ambiance. C’est de la folie en tribunes.","Je leur ai dit que j’étais tout sauf fou. Il y avait (Gianluigi) Buffon en face et il me connaissait très bien."],technique_jeu:["Aimé, ce jour-là, nous avait dit que les Brésiliens marquaient en zone et qu’on avait intérêt à sauter sur les corners. Sans cette réunion le matin, peut-être que je n’y serais pas allé sur les corners…"],ethique_justice:["Je trouve que le carton rouge est excessif et, une fois qu’il est pris, je me dis que c’est ma faute. C’est moi qui ai réagi, c’est moi le fautif."],anecdotes_vie_privee:["La finale de la Coupe du monde en France, je sais avec qui j’étais après le match, ce que j’ai fait, comment je l’ai fait : tout de suite après, dans les vestiaires, j’étais avec mon fils, avec mon épouse et avec la coupe."],preparation_condition_physique:["Je sais qu’on en a fait des caisses mais, moi, j’ai surtout mal vécu ma Coupe du monde parce que j’étais en marge des autres. Quand ils s’entraînaient, je me faisais soigner et, quand je m’entraînais, ils étaient au repos."],heritage_posterite:["Ma vie a changé complètement à ce moment-là. À tous les niveaux.","Tout fait partie d’une carrière, d’un homme… Tout ça, c’est juste moi."],psychologie_emotion:["Oui, vous sentez quand vous prenez le dessus. Oui, on l’utilise. À ce moment-là, c’est bien de se parler sur le terrain car l’adversaire vous voit, vous entend."]},date_publication:"13/07/2014",resume:"Peu de joueurs sont autant liés à l’histoire de la Coupe du monde. Avec les Brésiliens Pelé et Vava, et l’Allemand Paul Breitner, Zinédine Zidane est le seul à avoir marqué dans deux finales de Coupe du monde.",citation_forte:"J’ai gagné ce trophée, j’ai soulevé cette coupe : c’est pour ça que l’on joue au foot, finalement. Pour gagner des trophées.",archetypes_ids:["l_historien","le_patriote","le_supporter"],theme_citations:{parcours_professionnel:"J’ai gagné ce trophée, j’ai soulevé cette coupe : c’est pour ça que l’on joue au foot, finalement. Pour gagner des trophées.",vie_equipe:"J’ai toujours fait et je ferai toujours tout pour l’équipe. Ce n’est jamais pour moi, perso. Je n’ai jamais été égoïste et je ne le serai jamais.",ressentis_emotions:"Je savais bien que j’avais fait quelque chose de top, que gagner une finale de Coupe du monde et marquer deux fois, ça n’arrive pas tous les jours. La force qui t’envahit sur le moment, l’intensité émotionnelle… Je n’ai jamais revécu cela.",grands_moments_sportifs:"L’image est là. Je vois exactement ce que je fais. Je le revis avec l’ambiance. C’est de la folie en tribunes.",technique_jeu:"Aimé, ce jour-là, nous avait dit que les Brésiliens marquaient en zone et qu’on avait intérêt à sauter sur les corners. Sans cette réunion le matin, peut-être que je n’y serais pas allé sur les corners…",ethique_justice:"Je trouve que le carton rouge est excessif et, une fois qu’il est pris, je me dis que c’est ma faute. C’est moi qui ai réagi, c’est moi le fautif.",anecdotes_vie_privee:"La finale de la Coupe du monde en France, je sais avec qui j’étais après le match, ce que j’ai fait, comment je l’ai fait : tout de suite après, dans les vestiaires, j’étais avec mon fils, avec mon épouse et avec la coupe.",preparation_condition_physique:"Je sais qu’on en a fait des caisses mais, moi, j’ai surtout mal vécu ma Coupe du monde parce que j’étais en marge des autres. Quand ils s’entraînaient, je me faisais soigner et, quand je m’entraînais, ils étaient au repos.",heritage_posterite:"Ma vie a changé complètement à ce moment-là. À tous les niveaux.",psychologie_emotion:"Oui, vous sentez quand vous prenez le dessus. Oui, on l’utilise. À ce moment-là, c’est bien de se parler sur le terrain car l’adversaire vous voit, vous entend."},joueur:"Zinédine Zidane",temps_lecture:"10 min"},{slug:"miroslav-klose-2014",index:33,nom:"Miroslav Klose",surnom:null,pays:"Allemagne",mondial:"2014",poste:"Attaquant",image:"/cartes_itw/Klose.png",titre_interview:"« Et on récupérait le ballon, et on marquait encore… »",lu:!1,archetype:"L'historien",archetype_justification:"Grand serviteur du collectif, il est entré dans l'histoire à travers ses records et le souvenir du match historique contre le Brésil.",citations:{parcours_professionnel:[],contexte_historique:["Pour l’avoir vécu en 2006, on savait ce que représentait l’avantage de jouer à domicile : c’est une pression particulière et si tout ne s’enchaîne pas bien dès le début, elle peut devenir négative."],vie_equipe:["Quand notre équipe a cette capacité à courir sans le ballon, quand chacun est prêt à courir pour l’autre, c’est une équipe fantastique, on peut battre n’importe qui.","À la mi-temps (0-5), il n’y avait pas non plus d’euphorie."],ressentis_emotions:["Je me souviens qu’à 3-0 on s’est dit qu’il fallait continuer à jouer sérieux. C’est essentiel.","D’abord qu’on était en finale, parmi les deux meilleures équipes du monde, parce qu’on voulait absolument atteindre cette finale. Ensuite, seulement, on a pris conscience qu’on avait joué un match historique…"],grands_moments_sportifs:["On en parlera toujours… Ce n’est pas tous les jours qu’on marque quatre buts en six minutes !","C’est d’ailleurs allé tellement vite que ce n’est qu’après coup qu’on a appris qu’on avait marqué quatre buts en six minutes."],technique_jeu:["On voulait donc récupérer le ballon le plus vite possible et après la récupération, on savait qu’on pouvait leur faire mal en ayant tout de suite trois ou quatre joueurs qui se projettent vers l’avant.","On avait super bien travaillé les coups de pied arrêtés. Sur coup franc comme sur corner, on avait plein de combinaisons possibles, on était imprévisibles."],ethique_justice:["Personne ne commence à faire de petit pont, à jouer à la baballe, à se moquer de l’adversaire. Quand tu penses que les choses viennent toutes seules, tu tentes des choses que tu n’aurais jamais tentées. Notre équipe n’est pas comme ça."],anecdotes_vie_privee:[],preparation_condition_physique:[],heritage_posterite:["Un joueur ne gagne jamais un match à lui tout seul. Il peut faire de belles actions, marquer des buts mais une compétition, on la gagne toujours en équipe."],psychologie_emotion:["Pour les Brésiliens, ç’a été un choc. Après chaque but, ils se disaient : “Qu’est-ce qui s’est encore passé ? Qu’est-ce qui n’a pas marché ?”"]},date_publication:"06/07/2015",resume:"La demi-finale de Coupe du monde disputée il y a bientôt un an par le Brésil et l’Allemagne, le 8 juillet 2014 à Belo Horizonte, restera comme un match hors du temps, en tout cas comme l’un des plus fous de l’histoire du foot.",citation_forte:"Pour l’avoir vécu en 2006, on savait ce que représentait l’avantage de jouer à domicile : c’est une pression particulière et si tout ne s’enchaîne pas bien dès le début, elle peut devenir négative.",archetypes_ids:["le_patriote","le_supporter","le_curieux"],theme_citations:{contexte_historique:"Pour l’avoir vécu en 2006, on savait ce que représentait l’avantage de jouer à domicile : c’est une pression particulière et si tout ne s’enchaîne pas bien dès le début, elle peut devenir négative.",vie_equipe:"Quand notre équipe a cette capacité à courir sans le ballon, quand chacun est prêt à courir pour l’autre, c’est une équipe fantastique, on peut battre n’importe qui.",ressentis_emotions:"Je me souviens qu’à 3-0 on s’est dit qu’il fallait continuer à jouer sérieux. C’est essentiel.",grands_moments_sportifs:"On en parlera toujours… Ce n’est pas tous les jours qu’on marque quatre buts en six minutes !",technique_jeu:"On voulait donc récupérer le ballon le plus vite possible et après la récupération, on savait qu’on pouvait leur faire mal en ayant tout de suite trois ou quatre joueurs qui se projettent vers l’avant.",ethique_justice:"Personne ne commence à faire de petit pont, à jouer à la baballe, à se moquer de l’adversaire. Quand tu penses que les choses viennent toutes seules, tu tentes des choses que tu n’aurais jamais tentées. Notre équipe n’est pas comme ça.",heritage_posterite:"Un joueur ne gagne jamais un match à lui tout seul. Il peut faire de belles actions, marquer des buts mais une compétition, on la gagne toujours en équipe.",psychologie_emotion:"Pour les Brésiliens, ç’a été un choc. Après chaque but, ils se disaient : “Qu’est-ce qui s’est encore passé ? Qu’est-ce qui n’a pas marché ?”"},joueur:"Miroslav Klose",temps_lecture:"5 min"},{slug:"hugo-lloris-2018",index:34,nom:"Hugo Lloris",surnom:"Benjamin",pays:"France",mondial:"2018",poste:"Gardien",image:"/cartes_itw/Lloris-carte-interview.png",titre_interview:"« Au coup de sifflet final, pendant quelques minutes, tu es perdu, tu ne sais pas trop ce qui t’arrive »",lu:!1,archetype:"Amoureux du maillot",archetype_justification:"Capitaine exemplaire, son discours est centré sur la fierté de défendre le titre et les couleurs de la France.",citations:{parcours_professionnel:["Après l’Euro 2016, je reviens, et je me blesse à l’ischio. Après la Coupe du monde, dès le troisième match, je suis touché à la cuisse, et oui, là, c’est lié.","On a joué tous les trois jours depuis le début de la saison."],contexte_historique:["Parce que vous devenez immédiatement l’équipe à battre, d’abord.","Si on regarde les dernières Coupes du monde, les champions en titre ont plutôt subi des mésaventures…"],vie_equipe:["Je n’y pense pas tout seul, pas régulièrement, mais dès que je croise un coéquipier, tout revient, parce qu’on est liés par ça.","Paul et Ngolo sont tellement importants, par leur talent, mais aussi leur personnalité. Quand ils sont dans la pièce, il se passe quelque chose. On ne peut pas les remplacer."],ressentis_emotions:["Au coup de sifflet final. Il y a entre cinq et dix minutes où tu ne sais pas trop ce qui t’arrive, où tu te perds un peu, où émotionnellement, c’est très fort.","Je suis très fier d’avoir été champion du monde, mais ça n’a pas changé ma façon de vivre."],grands_moments_sportifs:["Mais l’avoir vécu en tant que capitaine, oui, c’est encore plus fort, parce que tu soulèves la Coupe en premier…","À 3-1 contre la Suisse, à l’Euro, on a forcément manqué de concentration, d’exigence, on a forcément cru que c’était fait."],technique_jeu:["Il va falloir s‘appuyer sur un socle défensif important, et solide, et compter sur la folie amenée par le talent offensif de nos joueurs.","À partir des huitièmes, contre l’Argentine, on a eu des discussions, oui, parce qu’on voulait être costauds, et que dans ce registre, on se sentait vraiment très forts."],ethique_justice:[],anecdotes_vie_privee:["Il y a une photo dans la salle de jeux des enfants, et une autre dans le salon, avec mes filles, sur la pelouse, avec la Coupe du monde, sous la pluie et les confettis, ce qui rend la photo encore plus jolie.","Ça fait partie de mon éducation, mes parents et mes grands-parents m’ont élevé avec ces valeurs, l’humilité, la pudeur, le travail."],preparation_condition_physique:["Le foot, c’est quand même à part : tu as dix mois de compétition, un mois de préparation où tu voyages beaucoup pour le club de l’autre côté du monde, et trois semaines de vacances au milieu. Cela laisse peu de temps à la tête au corps pour se reposer.","J’y ai pensé quand on a passé deux jours à Marseille avec Tottenham, en Ligue des champions, sous le soleil, au bord de la mer : le corps, tout de suite, allait bien mieux."],heritage_posterite:["C’est quelque chose qu’on ne nous enlèvera jamais, ça nous appartient. Les champions du monde 1998, on les voit toujours comme des champions du monde, et nous, ce sera pareil.","Champion du monde, tu l’es à vie. Après, tous les quatre ans, il y a un nouveau titre en jeu."],psychologie_emotion:["Moi je suis toujours resté accroché à mon quotidien, aux entraînements, au match suivant, parce que c’est la seule manière de rester performant.","On oublie parfois, dans le sport, à quel point il faut d’abord être prêt à souffrir pour gagner."]},date_publication:"19/11/2022",resume:"Au Qatar, il s’avance vers son quatrième Mondial. Il peut y devenir le Bleu le plus capé de l’histoire.",citation_forte:"Après l’Euro 2016, je reviens, et je me blesse à l’ischio. Après la Coupe du monde, dès le troisième match, je suis touché à la cuisse, et oui, là, c’est lié.",archetypes_ids:["le_curieux"],theme_citations:{parcours_professionnel:"Après l’Euro 2016, je reviens, et je me blesse à l’ischio. Après la Coupe du monde, dès le troisième match, je suis touché à la cuisse, et oui, là, c’est lié.",contexte_historique:"Parce que vous devenez immédiatement l’équipe à battre, d’abord.",vie_equipe:"Je n’y pense pas tout seul, pas régulièrement, mais dès que je croise un coéquipier, tout revient, parce qu’on est liés par ça.",ressentis_emotions:"Au coup de sifflet final. Il y a entre cinq et dix minutes où tu ne sais pas trop ce qui t’arrive, où tu te perds un peu, où émotionnellement, c’est très fort.",grands_moments_sportifs:"Mais l’avoir vécu en tant que capitaine, oui, c’est encore plus fort, parce que tu soulèves la Coupe en premier…",technique_jeu:"Il va falloir s‘appuyer sur un socle défensif important, et solide, et compter sur la folie amenée par le talent offensif de nos joueurs.",anecdotes_vie_privee:"Il y a une photo dans la salle de jeux des enfants, et une autre dans le salon, avec mes filles, sur la pelouse, avec la Coupe du monde, sous la pluie et les confettis, ce qui rend la photo encore plus jolie.",preparation_condition_physique:"Le foot, c’est quand même à part : tu as dix mois de compétition, un mois de préparation où tu voyages beaucoup pour le club de l’autre côté du monde, et trois semaines de vacances au milieu. Cela laisse peu de temps à la tête au corps pour se reposer.",heritage_posterite:"C’est quelque chose qu’on ne nous enlèvera jamais, ça nous appartient. Les champions du monde 1998, on les voit toujours comme des champions du monde, et nous, ce sera pareil.",psychologie_emotion:"Moi je suis toujours resté accroché à mon quotidien, aux entraînements, au match suivant, parce que c’est la seule manière de rester performant."},joueur:"Hugo Lloris",temps_lecture:"10 min"},{slug:"luka-modric-2018",index:35,nom:"Luka Modric",surnom:null,pays:"Croatie",mondial:"2018",poste:"Meneur de jeu",image:"/cartes_itw/jojo.png",titre_interview:"« Dégoûté par notre manque de baraka »",lu:!1,archetype:"Amoureux du maillot",archetype_justification:"Fier de porter le « maillot à damier », il a vécu une symbiose totale avec son pays lors de l'épopée de 2018.",citations:{parcours_professionnel:["J’avais treize ans et je jouais dans le club de ma ville de Zadar au moment de la Coupe du monde 1998."],contexte_historique:["Il y a d’abord la fierté d’avoir écrit une page historique du sport en Croatie."],vie_equipe:["Juste après le coup de sifflet final, j’étais évidemment déçu. Mais notre entraîneur a trouvé les mots pour nous remonter, nous rendre le sourire.","Avec notre sélectionneur et tout son staff, nous avons créé un groupe formidable, uni, en symbiose totale avec nos supporters."],ressentis_emotions:["Toute cette chaleur humaine te fait chavirer, elle te saoule littéralement de bonheur comme on dit parfois.","Je suis surtout dégoûté par notre manque de baraka ! Je dirais même que nous n’avons pas été chanceux un instant."],grands_moments_sportifs:["Il y a eu ce but contre son camp sur un coup franc pas évident et, après notre belle égalisation, la poisse du penalty."],technique_jeu:["D’autant plus que je pense que nous avons été l’équipe qui a le mieux joué sur l’ensemble du tournoi et, pendant une partie de la finale, nous avons fait mieux que tenir tête aux Français."],ethique_justice:["Perisic n’a pas touché le ballon de la main de façon volontaire.","J’ai entendu dire qu’avec un autre arbitrage cette rencontre aurait pu s’écrire autrement : pour moi, il est inutile de s’éterniser sur les épisodes en question. Cela ne sert à rien."],anecdotes_vie_privee:[],preparation_condition_physique:["Avec nos trois prolongations successives et nos deux séances de tirs au but, on a joué carrément un match de plus que la France, tout en disposant d’un jour de repos en moins qu’elle avant la finale. Tout cela a, bien sûr, joué."],heritage_posterite:["Cette récompense m’a touché parce qu’elle a été obtenue grâce au travail de toute l’équipe. Inutile d’ajouter que cela n’a rien de comparable avec le bonheur que m’aurait procuré le titre mondial.","Pour moi, jouer avec la sélection, porter ce maillot à damier, même à l’entraînement, m’a toujours procuré et me procure toujours un bonheur énorme. Je suis fier d’être le capitaine de cette sélection."],psychologie_emotion:["Je me souviens de l’état de tristesse qui nous envahissait au début de l’automne dernier, de notre moral au plus bas lors des derniers matches éliminatoires et cette qualification pour les barrages que nous sommes allés chercher à Kiev."]},date_publication:"24/07/2018",resume:"C’est une marée humaine. Une immense vague aux couleurs rouge et blanc qui a déferlé sur la route de l’équipe de Croatie, lundi dernier à Zagreb, lors de son retour au pays.",citation_forte:"J’avais treize ans et je jouais dans le club de ma ville de Zadar au moment de la Coupe du monde 1998.",archetypes_ids:["le_curieux"],theme_citations:{parcours_professionnel:"J’avais treize ans et je jouais dans le club de ma ville de Zadar au moment de la Coupe du monde 1998.",contexte_historique:"Il y a d’abord la fierté d’avoir écrit une page historique du sport en Croatie.",vie_equipe:"Juste après le coup de sifflet final, j’étais évidemment déçu. Mais notre entraîneur a trouvé les mots pour nous remonter, nous rendre le sourire.",ressentis_emotions:"Toute cette chaleur humaine te fait chavirer, elle te saoule littéralement de bonheur comme on dit parfois.",grands_moments_sportifs:"Il y a eu ce but contre son camp sur un coup franc pas évident et, après notre belle égalisation, la poisse du penalty.",technique_jeu:"D’autant plus que je pense que nous avons été l’équipe qui a le mieux joué sur l’ensemble du tournoi et, pendant une partie de la finale, nous avons fait mieux que tenir tête aux Français.",ethique_justice:"Perisic n’a pas touché le ballon de la main de façon volontaire.",preparation_condition_physique:"Avec nos trois prolongations successives et nos deux séances de tirs au but, on a joué carrément un match de plus que la France, tout en disposant d’un jour de repos en moins qu’elle avant la finale. Tout cela a, bien sûr, joué.",heritage_posterite:"Cette récompense m’a touché parce qu’elle a été obtenue grâce au travail de toute l’équipe. Inutile d’ajouter que cela n’a rien de comparable avec le bonheur que m’aurait procuré le titre mondial.",psychologie_emotion:"Je me souviens de l’état de tristesse qui nous envahissait au début de l’automne dernier, de notre moral au plus bas lors des derniers matches éliminatoires et cette qualification pour les barrages que nous sommes allés chercher à Kiev."},joueur:"Luka Modric",temps_lecture:"6 min"},{slug:"lionel-scaloni-2022",index:36,nom:"Lionel Scaloni",surnom:null,pays:"Argentine",mondial:"2022",poste:"Sélectionneur",image:"/cartes_itw/scaloni-carte-interview.png",titre_interview:"« Aucune équipe n’a eu peur de perdre »",lu:!1,archetype:"Le stratège",archetype_justification:"Il analyse chaque détail du jeu et adapte ses schémas tactiques pour changer l'équilibre du match.",citations:{parcours_professionnel:["J’ai ressenti une satisfaction absolue, celle d’avoir remporté un titre que seuls quelques entraîneurs ont pu obtenir."],contexte_historique:["Ce qui m’a plu, c’est qu’aucune des deux équipes n’a eu peur de perdre, une crainte pourtant très présente dans le monde actuel."],vie_equipe:["Mais avant de partir pour le stade, je n’ai pas pu finir mon discours, je me suis mis à pleurer en plein milieu… Tout le monde était très ému.","Puis j’ai pris ma famille et mon staff dans mes bras."],ressentis_emotions:["Je me suis alors dit : « Que le football peut être injuste ! »","À partir de la 80e minute, il y a eu de la frustration, de la joie, puis encore de la frustration et une issue heureuse pour nous. Ça m’étonnerait qu’on revoie un jour quelque chose de semblable."],grands_moments_sportifs:["Mbappé s’est appuyé sur (Marcus) Thuram et il a marqué un but spectaculaire, l’un des plus beaux en finale de Coupe du monde. Ils n’ont eu besoin que de quatre passes pour conclure. Quel golazo !","Sincèrement, je ne me souviens pas bien de l’arrêt de « Dibu » (Emiliano Martinez) face à Kolo Muani. Évidemment, j’ai vu ça comme une belle occasion pour la France, mais ça ne m’a pas paru si criant sur le moment."],technique_jeu:["On a remarqué que (Kylian) Mbappé aimait bien traîner devant lorsque la France n’avait pas la balle. [...] On a donc décidé d’avoir toujours deux joueurs prêts à intervenir sur lui en cas de perte de balle","Notre plan d’attaque a fonctionné comme on l’espérait, avec Angel (Di Maria) toujours prêt à recevoir le ballon sur l’aile gauche, même lorsque l’action démarrait à l’opposé. C’est un des joueurs les plus imprévisibles qui soit en un-contre-un"],ethique_justice:["Dans le but, « Dibu » est quelqu’un qui rayonne, qui transmet son optimisme aux autres. [...] Après, il a su ressortir ce qu’il avait appris sur le potrero (le terrain vague), dans son quartier, pour essayer de déconcentrer ses adversaires, tout en respectant les règles."],anecdotes_vie_privee:["Ce sweat-shirt aux couleurs de la France que j’ai mis pour cette interview ? Je l’ai attrapé en partant de chez moi et sur le chemin ma femme m’a dit : « Tu vas vraiment mettre cette veste ? »"],preparation_condition_physique:["Avant tout, on laisse les joueurs récupérer, on leur demande si l’un d’entre eux a le moindre pépin physique, puis il reste deux, trois minutes à peine pour faire quelques réajustements."],heritage_posterite:["J’étais également super content que Leo puisse enfin brandir ce trophée. Il l’a tellement mérité, après s’être tant battu pour ça.","À la fin du match, un supporter argentin est venu sur la pelouse et m’a offert une réplique du maillot que je portais avec l’Argentine lors de la Coupe du monde des moins de 20 ans en 1997 en Malaisie (remportée par l’Albiceleste)."],psychologie_emotion:["C’est un moment très difficile, que j’aimerais supprimer si je le pouvais, car là tu te mets à cogiter, à penser à un aspect que tu aurais pu oublier, à des choses négatives qui pourraient arriver durant le match…","Deux à zéro est un résultat trompeur, car il te donne des ailes, tu as la sensation d’avoir fait la différence. Mais l’équipe qui revient à un but reprend espoir, tandis que celle qui gagne se dit : « Putain, j’avais la victoire à portée de main et maintenant tout est remis en cause. »"]},date_publication:"03/02/2024",resume:"Le sélectionneur des champions du monde argentins raconte, pour France Football, la finale d’anthologie face à l’équipe de France fin 2022, marquée par de spectaculaires rebondissements. Un souvenir heureux pour lui, douloureux pour nous.",citation_forte:"J’ai ressenti une satisfaction absolue, celle d’avoir remporté un titre que seuls quelques entraîneurs ont pu obtenir.",archetypes_ids:["le_curieux"],theme_citations:{parcours_professionnel:"J’ai ressenti une satisfaction absolue, celle d’avoir remporté un titre que seuls quelques entraîneurs ont pu obtenir.",contexte_historique:"Ce qui m’a plu, c’est qu’aucune des deux équipes n’a eu peur de perdre, une crainte pourtant très présente dans le monde actuel.",vie_equipe:"Mais avant de partir pour le stade, je n’ai pas pu finir mon discours, je me suis mis à pleurer en plein milieu… Tout le monde était très ému.",ressentis_emotions:"Je me suis alors dit : « Que le football peut être injuste ! »",grands_moments_sportifs:"Mbappé s’est appuyé sur (Marcus) Thuram et il a marqué un but spectaculaire, l’un des plus beaux en finale de Coupe du monde. Ils n’ont eu besoin que de quatre passes pour conclure. Quel golazo !",technique_jeu:"On a remarqué que (Kylian) Mbappé aimait bien traîner devant lorsque la France n’avait pas la balle. [...] On a donc décidé d’avoir toujours deux joueurs prêts à intervenir sur lui en cas de perte de balle",ethique_justice:"Dans le but, « Dibu » est quelqu’un qui rayonne, qui transmet son optimisme aux autres. [...] Après, il a su ressortir ce qu’il avait appris sur le potrero (le terrain vague), dans son quartier, pour essayer de déconcentrer ses adversaires, tout en respectant les règles.",anecdotes_vie_privee:"Ce sweat-shirt aux couleurs de la France que j’ai mis pour cette interview ? Je l’ai attrapé en partant de chez moi et sur le chemin ma femme m’a dit : « Tu vas vraiment mettre cette veste ? »",preparation_condition_physique:"Avant tout, on laisse les joueurs récupérer, on leur demande si l’un d’entre eux a le moindre pépin physique, puis il reste deux, trois minutes à peine pour faire quelques réajustements.",heritage_posterite:"J’étais également super content que Leo puisse enfin brandir ce trophée. Il l’a tellement mérité, après s’être tant battu pour ça.",psychologie_emotion:"C’est un moment très difficile, que j’aimerais supprimer si je le pouvais, car là tu te mets à cogiter, à penser à un aspect que tu aurais pu oublier, à des choses négatives qui pourraient arriver durant le match…"},joueur:"Lionel Scaloni",temps_lecture:"11 min"}];Object.fromEntries(a.map(e=>[e.slug,e])),e.s(["JOUEURS",0,a])}]);